const advancedReverseEngineeringHtml = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>RE//06 — Advanced Reverse Engineering</title>\n<style>\n@import url('https://fonts.googleapis.com/css2?family=VT323&family=Black+Ops+One&family=Share+Tech+Mono&family=Teko:wght@300;400;600;700&display=swap');\n\n:root {\n  --void:   #02040a;\n  --void2:  #050a12;\n  --void3:  #080f1c;\n  --phos:   #0aff5a;   /* phosphor green — main */\n  --phos2:  #07cc48;\n  --phos3:  #05992e;\n  --phos4:  #033a14;\n  --amber:  #ffb800;   /* amber CRT */\n  --amber2: #cc8800;\n  --red:    #ff1a2e;\n  --cyan:   #00e8ff;\n  --cyan2:  #00aabb;\n  --white:  #d0f0e0;\n  --dim:    #1a4028;\n  --muted:  #0d2418;\n  --rule:   #0a1e10;\n\n  --vt: 'VT323', monospace;\n  --ops: 'Black Ops One', cursive;\n  --mono: 'Share Tech Mono', monospace;\n  --teko: 'Teko', sans-serif;\n}\n\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\nhtml { scroll-behavior: smooth; }\n\nbody {\n  background: var(--void);\n  color: var(--phos);\n  font-family: var(--mono);\n  min-height: 100vh;\n  overflow-x: hidden;\n  cursor: crosshair;\n}\n\n/* ── CRT EFFECTS ── */\nbody::before {\n  content: '';\n  position: fixed; inset: 0;\n  background: repeating-linear-gradient(\n    0deg,\n    transparent 0px,\n    transparent 3px,\n    rgba(0,0,0,.12) 3px,\n    rgba(0,0,0,.12) 4px\n  );\n  pointer-events: none; z-index: 9000;\n  animation: scanroll 8s linear infinite;\n}\n@keyframes scanroll {\n  0%   { background-position: 0 0; }\n  100% { background-position: 0 400px; }\n}\n\n/* Phosphor glow vignette */\nbody::after {\n  content: '';\n  position: fixed; inset: 0;\n  background: radial-gradient(\n    ellipse 85% 85% at 50% 50%,\n    transparent 60%,\n    rgba(2,4,10,.8) 100%\n  );\n  pointer-events: none; z-index: 8999;\n}\n\n/* Phosphor text glow */\n.glow { text-shadow: 0 0 8px var(--phos), 0 0 20px rgba(10,255,90,.3); }\n.glow-a { text-shadow: 0 0 8px var(--amber), 0 0 20px rgba(255,184,0,.3); }\n.glow-r { text-shadow: 0 0 8px var(--red), 0 0 20px rgba(255,26,46,.3); }\n.glow-c { text-shadow: 0 0 8px var(--cyan), 0 0 20px rgba(0,232,255,.3); }\n\n.z1 { position: relative; z-index: 1; }\n\n/* ── OSCILLOSCOPE HEADER / NAV ── */\nnav {\n  position: sticky; top: 0; z-index: 200;\n  background: var(--void);\n  border-bottom: 2px solid var(--phos3);\n  display: flex; align-items: stretch;\n  overflow-x: auto; scrollbar-width: none;\n  box-shadow: 0 0 20px rgba(10,255,90,.1);\n}\nnav::-webkit-scrollbar { display: none; }\n\n.nav-ident {\n  display: flex; align-items: center; gap: 12px;\n  padding: 0 20px;\n  border-right: 2px solid var(--phos3);\n  flex-shrink: 0;\n}\n.nav-badge {\n  font-family: var(--ops);\n  font-size: .75rem;\n  letter-spacing: 2px;\n  color: var(--void);\n  background: var(--phos);\n  padding: 3px 10px;\n  clip-path: polygon(8px 0%, 100% 0%, calc(100% - 8px) 100%, 0% 100%);\n  white-space: nowrap;\n}\n.nav-title {\n  font-family: var(--vt);\n  font-size: 1.1rem;\n  letter-spacing: 3px;\n  color: var(--phos);\n  white-space: nowrap;\n}\n\n.ntabs { display: flex; }\n.ntab {\n  font-family: var(--mono);\n  font-size: .6rem;\n  letter-spacing: 1.5px;\n  text-transform: uppercase;\n  padding: 0 16px;\n  cursor: pointer;\n  color: var(--phos3);\n  background: none; border: none;\n  border-right: 1px solid var(--muted);\n  white-space: nowrap;\n  transition: all .15s;\n  position: relative;\n}\n.ntab:hover { color: var(--phos); background: rgba(10,255,90,.04); }\n.ntab.active {\n  color: var(--void);\n  background: var(--phos3);\n  font-weight: 700;\n}\n.ntab.active::after {\n  content: '▶';\n  position: absolute; right: 4px; top: 50%;\n  transform: translateY(-50%);\n  font-size: .5rem;\n  color: var(--phos);\n}\n\n/* ── HERO / SCOPE DISPLAY ── */\n.hero {\n  padding: 0;\n  border-bottom: 2px solid var(--phos3);\n  display: grid;\n  grid-template-columns: 1fr 320px;\n  position: relative;\n  overflow: hidden;\n}\n@media(max-width:780px) { .hero { grid-template-columns: 1fr; } }\n\n/* Oscilloscope trace in hero background */\n.hero-trace {\n  position: absolute; inset: 0;\n  opacity: .07; pointer-events: none;\n  overflow: hidden;\n}\n\n.hero-main {\n  padding: 48px 48px 40px;\n  border-right: 2px solid var(--phos4);\n  position: relative;\n}\n\n.hero-module-tag {\n  font-family: var(--mono);\n  font-size: .58rem;\n  letter-spacing: 5px;\n  color: var(--phos3);\n  margin-bottom: 16px;\n  display: flex; align-items: center; gap: 12px;\n}\n.hero-module-tag::before {\n  content: '';\n  display: block; width: 3px; height: 3px;\n  background: var(--phos);\n  box-shadow: 0 0 6px var(--phos);\n  border-radius: 50%;\n  animation: blink 1.2s step-end infinite;\n}\n@keyframes blink { 0%,100%{opacity:1} 50%{opacity:0} }\n\n.hero-h1 {\n  font-family: var(--ops);\n  font-size: clamp(2.8rem, 7vw, 5.5rem);\n  line-height: .92;\n  letter-spacing: 2px;\n  margin-bottom: 20px;\n  color: var(--phos);\n  text-shadow: 0 0 30px rgba(10,255,90,.4), 0 0 60px rgba(10,255,90,.1);\n}\n.hero-h1 .hl { color: var(--amber); text-shadow: 0 0 20px rgba(255,184,0,.5); }\n\n.hero-desc {\n  font-family: var(--mono);\n  font-size: .82rem;\n  color: var(--phos3);\n  line-height: 1.8;\n  max-width: 480px;\n  margin-bottom: 24px;\n  letter-spacing: .5px;\n}\n\n.hero-chips { display: flex; flex-wrap: wrap; gap: 6px; }\n.hchip {\n  font-family: var(--mono);\n  font-size: .56rem;\n  letter-spacing: 2px;\n  padding: 4px 10px;\n  border: 1px solid var(--phos3);\n  color: var(--phos3);\n  text-transform: uppercase;\n  clip-path: polygon(6px 0%, 100% 0%, calc(100% - 6px) 100%, 0% 100%);\n}\n\n.hero-panel {\n  padding: 0;\n  background: var(--void2);\n  display: flex; flex-direction: column;\n}\n.hero-panel-row {\n  flex: 1;\n  padding: 16px 20px;\n  border-bottom: 1px solid var(--muted);\n  display: flex; flex-direction: column; justify-content: center;\n}\n.hero-panel-row:last-child { border-bottom: none; }\n.hpr-label {\n  font-family: var(--mono);\n  font-size: .5rem;\n  letter-spacing: 3px;\n  color: var(--dim);\n  text-transform: uppercase;\n  margin-bottom: 4px;\n}\n.hpr-value {\n  font-family: var(--vt);\n  font-size: 1.3rem;\n  letter-spacing: 2px;\n  color: var(--amber);\n  text-shadow: 0 0 10px rgba(255,184,0,.4);\n}\n.hpr-sub {\n  font-family: var(--mono);\n  font-size: .6rem;\n  color: var(--phos3);\n  margin-top: 2px;\n}\n\n/* ── MODULE / WRAPPER ── */\n.module { display: none; }\n.module.active { display: block; }\n.wrapper { max-width: 1200px; margin: 0 auto; padding: 40px 48px 80px; }\n@media(max-width:640px) { .wrapper { padding: 24px 16px 60px; } }\n\n/* ── SECTION HEADER ── */\n.sh {\n  margin-bottom: 32px;\n  padding-bottom: 16px;\n  border-bottom: 1px solid var(--phos4);\n  display: flex; align-items: flex-start; gap: 16px;\n}\n.sh-marker {\n  font-family: var(--vt);\n  font-size: 3.5rem;\n  line-height: 1;\n  color: var(--phos4);\n  flex-shrink: 0;\n  margin-top: 4px;\n}\n.sh-body {}\n.sh-eyebrow {\n  font-family: var(--mono);\n  font-size: .52rem;\n  letter-spacing: 4px;\n  color: var(--dim);\n  margin-bottom: 6px;\n  text-transform: uppercase;\n}\n.sh-title {\n  font-family: var(--ops);\n  font-size: 1.6rem;\n  letter-spacing: 2px;\n  color: var(--phos);\n  margin-bottom: 6px;\n  text-shadow: 0 0 15px rgba(10,255,90,.3);\n}\n.sh-title .hl { color: var(--amber); }\n.sh-desc {\n  font-family: var(--mono);\n  font-size: .78rem;\n  color: var(--phos3);\n  line-height: 1.7;\n  max-width: 680px;\n}\n\n/* ── GRIDS ── */\n.g2 { display: grid; grid-template-columns: repeat(2,1fr); gap: 12px; }\n.g3 { display: grid; grid-template-columns: repeat(3,1fr); gap: 10px; }\n.gasym { display: grid; grid-template-columns: 1.5fr 1fr; gap: 12px; }\n@media(max-width:860px) { .g2,.g3,.gasym { grid-template-columns:1fr; } }\n\n/* ── CARDS — panel/instrument look ── */\n.card {\n  background: var(--void2);\n  border: 1px solid var(--phos4);\n  border-radius: 0;\n  padding: 18px 20px;\n  position: relative;\n  overflow: hidden;\n  transition: border-color .2s, box-shadow .2s;\n}\n.card:hover {\n  border-color: var(--phos3);\n  box-shadow: 0 0 16px rgba(10,255,90,.08), inset 0 0 16px rgba(10,255,90,.02);\n}\n\n/* corner bracket decoration */\n.card::before, .card::after {\n  content: '';\n  position: absolute;\n  width: 8px; height: 8px;\n  border-color: var(--phos3);\n  border-style: solid;\n  opacity: .6;\n}\n.card::before { top: 4px; left: 4px; border-width: 1px 0 0 1px; }\n.card::after  { bottom: 4px; right: 4px; border-width: 0 1px 1px 0; }\n\n/* card accent variants */\n.ca { border-top: 2px solid var(--amber3); }\n.ca:hover { border-top-color: var(--amber); box-shadow: 0 0 16px rgba(255,184,0,.08); }\n.cr { border-top: 2px solid rgba(255,26,46,.4); }\n.cr:hover { border-top-color: var(--red); }\n.cc { border-top: 2px solid rgba(0,232,255,.2); }\n.cc:hover { border-top-color: var(--cyan2); }\n\n.clabel {\n  font-family: var(--mono);\n  font-size: .5rem;\n  letter-spacing: 3px;\n  color: var(--dim);\n  text-transform: uppercase;\n  margin-bottom: 6px;\n}\n.ctitle {\n  font-family: var(--ops);\n  font-size: 1rem;\n  letter-spacing: 1px;\n  color: var(--phos);\n  margin-bottom: 10px;\n  line-height: 1.1;\n}\n.ctitle.amber { color: var(--amber); }\n.ctitle.red   { color: var(--red); }\n.ctitle.cyan  { color: var(--cyan2); }\n.cbody {\n  font-family: var(--mono);\n  font-size: .75rem;\n  color: var(--phos3);\n  line-height: 1.75;\n}\n.cbody strong { color: var(--phos); }\n.cbody code {\n  font-family: var(--mono);\n  font-size: .72rem;\n  color: var(--amber);\n  background: rgba(255,184,0,.07);\n  padding: 1px 4px;\n  border: 1px solid rgba(255,184,0,.15);\n}\n\n/* ── CODE BLOCKS — terminal/hex dump style ── */\n.cb {\n  background: #010308;\n  border: 1px solid var(--phos4);\n  border-left: 3px solid var(--cb-accent, var(--phos3));\n  padding: 14px 16px;\n  font-family: var(--mono);\n  font-size: .68rem;\n  line-height: 1.95;\n  overflow-x: auto;\n  margin: 10px 0;\n  color: #1a4028;\n  position: relative;\n  box-shadow: inset 0 0 30px rgba(10,255,90,.02);\n}\n.cb .tag {\n  position: absolute; top: 5px; right: 8px;\n  font-size: .48rem; letter-spacing: 2px;\n  color: rgba(10,255,90,.25); text-transform: uppercase;\n}\n.K { color: #0aff5a; font-weight: 700; }\n.F { color: #ffb800; }\n.S { color: #aaddbb; }\n.N { color: #ff8844; }\n.C { color: #0d2818; font-style: italic; }\n.V { color: #66bb88; }\n.H { color: #88ccaa; }\n.R { color: #ff1a2e; }\n.G { color: #0aff5a; }\n.Y { color: #ffb800; }\n.CY { color: #00e8ff; }\n.W { color: #d0f0e0; }\n.P { color: #cc88ff; }\n.DIM { color: #0d2818; }\n\n/* ── HEX DUMP DISPLAY ── */\n.hexdump {\n  background: #010308;\n  border: 1px solid var(--phos4);\n  padding: 14px 16px;\n  font-family: var(--mono);\n  font-size: .67rem;\n  line-height: 1.9;\n  overflow-x: auto;\n  color: #1a4028;\n  margin: 10px 0;\n}\n.hex-addr { color: var(--phos4); }\n.hex-byte { color: var(--phos3); }\n.hex-byte.hl { color: var(--amber); font-weight: 700; }\n.hex-byte.red { color: var(--red); }\n.hex-byte.cyan { color: var(--cyan2); }\n.hex-ascii { color: var(--dim); margin-left: 10px; }\n.hex-ascii .hl { color: var(--phos); }\n\n/* ── ALERT ── */\n.alert {\n  border: 1px solid;\n  padding: 10px 14px;\n  margin: 10px 0;\n  font-family: var(--mono);\n  font-size: .73rem;\n  line-height: 1.65;\n}\n.alert strong { font-weight: 700; }\n.a-warn { border-color: rgba(255,184,0,.4); color: var(--amber2); background: rgba(255,184,0,.04); }\n.a-info { border-color: rgba(0,232,255,.3); color: var(--cyan2); background: rgba(0,232,255,.04); }\n.a-ok   { border-color: rgba(10,255,90,.3); color: var(--phos3); background: rgba(10,255,90,.04); }\n.a-err  { border-color: rgba(255,26,46,.4); color: var(--red); background: rgba(255,26,46,.04); }\n\n/* ── TABLE ── */\n.dtable { width: 100%; border-collapse: collapse; margin: 10px 0; }\n.dtable th {\n  font-family: var(--mono);\n  font-size: .52rem;\n  letter-spacing: 2px;\n  text-transform: uppercase;\n  padding: 8px 12px;\n  text-align: left;\n  background: var(--phos4);\n  color: var(--phos);\n  border: 1px solid var(--phos4);\n}\n.dtable td {\n  font-family: var(--mono);\n  font-size: .72rem;\n  padding: 8px 12px;\n  border: 1px solid var(--muted);\n  vertical-align: top;\n  line-height: 1.5;\n  color: var(--phos3);\n}\n.dtable tr:nth-child(even) td { background: rgba(10,255,90,.02); }\n.dtable tr:hover td { background: rgba(10,255,90,.04); color: var(--phos); }\n.dtable td strong { color: var(--phos); }\n.dtable td code { font-family: var(--mono); color: var(--amber); }\n.tc-r { color: var(--red) !important; font-weight: 700; }\n.tc-y { color: var(--amber) !important; font-weight: 700; }\n.tc-g { color: var(--phos2) !important; font-weight: 700; }\n.tc-c { color: var(--cyan2) !important; font-weight: 700; }\n\n/* ── DIVIDER ── */\n.divline {\n  height: 1px;\n  background: linear-gradient(90deg, transparent, var(--phos4), transparent);\n  margin: 24px 0;\n}\n\n/* ── BADGES ── */\n.badges { display: flex; flex-wrap: wrap; gap: 5px; margin-top: 10px; }\n.badge {\n  font-family: var(--mono);\n  font-size: .5rem;\n  letter-spacing: 1.5px;\n  padding: 2px 8px;\n  border: 1px solid;\n  text-transform: uppercase;\n  clip-path: polygon(5px 0%, 100% 0%, calc(100% - 5px) 100%, 0% 100%);\n}\n.bg { color: var(--phos3); border-color: var(--phos3); background: rgba(10,255,90,.05); }\n.ba { color: var(--amber2); border-color: var(--amber3); background: rgba(255,184,0,.05); }\n.br { color: var(--red); border-color: rgba(255,26,46,.4); background: rgba(255,26,46,.05); }\n.bc { color: var(--cyan2); border-color: rgba(0,232,255,.3); background: rgba(0,232,255,.05); }\n\n/* ── IN-PAGE TABS ── */\n.itabs {\n  display: flex; border-bottom: 1px solid var(--phos4);\n  margin-bottom: 0; overflow-x: auto; scrollbar-width: none;\n}\n.itabs::-webkit-scrollbar { display: none; }\n.itab {\n  font-family: var(--mono);\n  font-size: .56rem;\n  letter-spacing: 2px;\n  text-transform: uppercase;\n  padding: 9px 14px;\n  cursor: pointer;\n  color: var(--dim);\n  background: none; border: none;\n  border-bottom: 2px solid transparent;\n  margin-bottom: -1px;\n  white-space: nowrap;\n  transition: all .15s;\n}\n.itab:hover { color: var(--phos3); }\n.itab.active { color: var(--phos); border-bottom-color: var(--phos); }\n.ipanel { display: none; padding-top: 20px; }\n.ipanel.active { display: block; }\n\n/* ── QUIZ ── */\n.qcard {\n  background: var(--void2);\n  border: 1px solid var(--phos4);\n  padding: 20px;\n  margin-bottom: 10px;\n  position: relative;\n}\n.qcard::before, .qcard::after {\n  content: ''; position: absolute;\n  width: 6px; height: 6px;\n  border-color: var(--phos3); border-style: solid; opacity: .5;\n}\n.qcard::before { top: 3px; left: 3px; border-width: 1px 0 0 1px; }\n.qcard::after  { bottom: 3px; right: 3px; border-width: 0 1px 1px 0; }\n\n.qnum { font-family: var(--mono); font-size: .5rem; letter-spacing: 3px; color: var(--dim); margin-bottom: 8px; text-transform: uppercase; }\n.qtext { font-family: var(--vt); font-size: 1.25rem; color: var(--phos); margin-bottom: 14px; line-height: 1.35; letter-spacing: .5px; }\n.qopts { display: flex; flex-direction: column; gap: 5px; }\n.qopt {\n  font-family: var(--mono);\n  font-size: .68rem;\n  padding: 9px 12px;\n  border: 1px solid var(--muted);\n  background: var(--void);\n  color: var(--phos3);\n  text-align: left;\n  cursor: pointer;\n  transition: all .15s;\n  line-height: 1.4;\n}\n.qopt:hover:not(.locked) {\n  border-color: var(--phos3);\n  color: var(--phos);\n  background: rgba(10,255,90,.03);\n  box-shadow: 0 0 8px rgba(10,255,90,.06);\n}\n.qopt.correct { border-color: var(--phos2); background: rgba(10,255,90,.08); color: var(--phos); }\n.qopt.wrong   { border-color: rgba(255,26,46,.5); background: rgba(255,26,46,.05); color: var(--red); }\n.qexplain {\n  margin-top: 10px;\n  padding: 10px 14px;\n  background: #010308;\n  border-left: 2px solid var(--amber3);\n  font-family: var(--mono);\n  font-size: .7rem;\n  color: var(--phos3);\n  line-height: 1.7;\n  display: none;\n}\n.qexplain.show { display: block; }\n.qexplain strong { color: var(--amber); }\n.qexplain code { color: var(--phos); }\n\n.score-panel {\n  background: var(--void2);\n  border: 1px solid var(--phos3);\n  padding: 24px;\n  margin-top: 16px;\n  text-align: center;\n  box-shadow: 0 0 30px rgba(10,255,90,.1);\n}\n.score-big { font-family: var(--vt); font-size: 4rem; color: var(--phos); line-height: 1; margin-bottom: 6px; text-shadow: 0 0 20px rgba(10,255,90,.5); }\n.score-sub { font-family: var(--mono); font-size: .58rem; letter-spacing: 3px; color: var(--dim); margin-bottom: 14px; }\n.score-bar { height: 3px; background: var(--muted); max-width: 300px; margin: 0 auto 16px; border: none; }\n.score-fill { height: 100%; transition: width .5s; }\n.reset-btn { font-family: var(--mono); font-size: .58rem; letter-spacing: 2px; text-transform: uppercase; padding: 8px 20px; background: none; color: var(--phos3); border: 1px solid var(--phos3); cursor: pointer; transition: all .2s; clip-path: polygon(6px 0%, 100% 0%, calc(100% - 6px) 100%, 0% 100%); }\n.reset-btn:hover { background: rgba(10,255,90,.08); color: var(--phos); }\n\n/* ── OSCILLOSCOPE WAVEFORM SVG ── */\n.scope-svg {\n  width: 100%;\n  height: 64px;\n  overflow: hidden;\n  background: #010308;\n  border: 1px solid var(--phos4);\n  margin: 10px 0;\n}\n\n/* ── ASSEMBLY LINE DISPLAY ── */\n.asm-line {\n  display: flex;\n  gap: 0;\n  font-family: var(--mono);\n  font-size: .7rem;\n  line-height: 1.85;\n  padding: 2px 0;\n  border-bottom: 1px solid rgba(10,255,90,.04);\n  transition: background .1s;\n}\n.asm-line:hover { background: rgba(10,255,90,.04); }\n.asm-addr { color: var(--phos4); min-width: 100px; flex-shrink: 0; }\n.asm-bytes { color: var(--dim); min-width: 150px; flex-shrink: 0; }\n.asm-mnem { color: var(--amber); min-width: 80px; flex-shrink: 0; }\n.asm-ops { color: var(--phos3); flex: 1; }\n.asm-cmt { color: var(--phos4); font-style: italic; }\n.asm-line.bp .asm-addr::before { content: '● '; color: var(--red); }\n.asm-line.hi { background: rgba(10,255,90,.06); }\n.asm-line.hi .asm-mnem { color: var(--phos); }\n</style>\n</head>\n<body>\n\n<!-- NAV -->\n<nav class=\"z1\">\n  <div class=\"nav-ident\">\n    <div class=\"nav-badge\">RE//06</div>\n    <div class=\"nav-title\">ADVANCED REVERSE ENGINEERING</div>\n  </div>\n  <div class=\"ntabs\">\n    <button class=\"ntab active\" onclick=\"sw('overview',this)\">Overview</button>\n    <button class=\"ntab\" onclick=\"sw('packing',this)\">Packers</button>\n    <button class=\"ntab\" onclick=\"sw('antianalysis',this)\">Anti-Analysis</button>\n    <button class=\"ntab\" onclick=\"sw('shellcode',this)\">Shellcode</button>\n    <button class=\"ntab\" onclick=\"sw('obfuscation',this)\">Obfuscation</button>\n    <button class=\"ntab\" onclick=\"sw('unpacking',this)\">Unpacking Lab</button>\n    <button class=\"ntab\" onclick=\"sw('advanced',this)\">Advanced TTPs</button>\n    <button class=\"ntab\" onclick=\"sw('quiz',this)\">Exam</button>\n  </div>\n</nav>\n\n<!-- HERO -->\n<div class=\"hero z1\">\n  <svg class=\"hero-trace\" viewBox=\"0 0 1000 200\" preserveAspectRatio=\"none\">\n    <polyline points=\"0,100 50,100 60,20 70,180 80,20 90,180 100,100 200,100 210,60 230,140 250,100 350,100 360,30 380,170 400,100 500,100 510,80 520,120 530,80 540,120 550,100 650,100 660,50 680,150 700,100 800,100 810,40 830,160 850,100 950,100 960,70 980,130 1000,100\"\n      fill=\"none\" stroke=\"#0aff5a\" stroke-width=\"2\"/>\n  </svg>\n  <div class=\"hero-main\">\n    <div class=\"hero-module-tag\">// Extension Module 06 // Advanced Reverse Engineering //</div>\n    <h1 class=\"hero-h1\">UNPACK.<br><span class=\"hl\">DEFEAT.</span><br>DISSECT.</h1>\n    <p class=\"hero-desc\">Packers, protectors, and polymorphic engines. Anti-debug, anti-VM, anti-sandbox evasion chains. Shellcode analysis from raw bytes to logic. Obfuscation patterns and how to dismantle them. The deepest layer of the analyst's craft.</p>\n    <div class=\"hero-chips\">\n      <span class=\"hchip\">Packer Analysis</span>\n      <span class=\"hchip\">OEP Recovery</span>\n      <span class=\"hchip\">Anti-Debug Defeat</span>\n      <span class=\"hchip\">Shellcode RE</span>\n      <span class=\"hchip\">Metamorphic Engines</span>\n      <span class=\"hchip\">Obfuscation</span>\n    </div>\n  </div>\n  <div class=\"hero-panel z1\">\n    <div class=\"hero-panel-row\">\n      <div class=\"hpr-label\">Prerequisite</div>\n      <div class=\"hpr-value\">MOD 03</div>\n      <div class=\"hpr-sub\">Basic RE skills required</div>\n    </div>\n    <div class=\"hero-panel-row\">\n      <div class=\"hpr-label\">Primary Tool</div>\n      <div class=\"hpr-value\">x64DBG</div>\n      <div class=\"hpr-sub\">+ Ghidra + ScyllaHide</div>\n    </div>\n    <div class=\"hero-panel-row\">\n      <div class=\"hpr-label\">Difficulty</div>\n      <div class=\"hpr-value\">HARD</div>\n      <div class=\"hpr-sub\">Advanced / Expert</div>\n    </div>\n    <div class=\"hero-panel-row\">\n      <div class=\"hpr-label\">ATT&CK</div>\n      <div class=\"hpr-value\">T1027</div>\n      <div class=\"hpr-sub\">Obfuscation + sub-techniques</div>\n    </div>\n  </div>\n</div>\n\n<!-- ═══════════════ OVERVIEW ═══════════════ -->\n<div class=\"module active z1\" id=\"mod-overview\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-marker\">06</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Module Map //</div>\n      <div class=\"sh-title\">Why <span class=\"hl\">Advanced</span> RE Matters</div>\n      <div class=\"sh-desc\">Modern malware is never handed to you in plain form. Every sophisticated sample employs multiple layers of protection: packing, encryption, anti-analysis tricks, and obfuscated shellcode. Defeating these layers is prerequisite to any meaningful analysis.</div>\n    </div>\n  </div>\n\n  <div class=\"g3\" style=\"margin-bottom:14px\">\n    <div class=\"card ca\">\n      <div class=\"clabel\">Layer 1</div>\n      <div class=\"ctitle amber\">PACKERS & PROTECTORS</div>\n      <div class=\"cbody\">Compresses or encrypts the real PE. A small stub decompresses/decrypts at runtime. Entropy >7.0. Disassembly of the stub reveals the unpacking algorithm. <strong>Goal: reach the OEP (Original Entry Point) and dump the clean PE.</strong></div>\n      <div class=\"badges\"><span class=\"badge ba\">UPX</span><span class=\"badge ba\">MPRESS</span><span class=\"badge ba\">Themida</span><span class=\"badge ba\">VMProtect</span></div>\n    </div>\n    <div class=\"card ca\">\n      <div class=\"clabel\">Layer 2</div>\n      <div class=\"ctitle amber\">ANTI-ANALYSIS</div>\n      <div class=\"cbody\">Actively detects debuggers, VMs, and sandboxes. If detected, the malware behaves differently or terminates. <strong>Goal: defeat every check so the real payload executes during analysis.</strong></div>\n      <div class=\"badges\"><span class=\"badge br\">Anti-Debug</span><span class=\"badge br\">Anti-VM</span><span class=\"badge br\">Timing</span></div>\n    </div>\n    <div class=\"card ca\">\n      <div class=\"clabel\">Layer 3</div>\n      <div class=\"ctitle amber\">SHELLCODE & OBFUSCATION</div>\n      <div class=\"cbody\">Position-independent code, API hashing, string encryption, control-flow flattening. <strong>Goal: recover the original logic from what looks like meaningless data or spaghetti code.</strong></div>\n      <div class=\"badges\"><span class=\"badge bc\">PIC</span><span class=\"badge bc\">API Hash</span><span class=\"badge bc\">CFF</span></div>\n    </div>\n  </div>\n\n  <!-- The RE ladder -->\n  <div class=\"card\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Skill Progression</div>\n    <div class=\"ctitle\">ADVANCED RE COMPETENCY LADDER</div>\n    <div class=\"cb\">\n<span class=\"G\">Level 1</span>  Basic static: strings, imports, PE structure              ← Module 03\n<span class=\"G\">Level 2</span>  Basic dynamic: Procmon, Wireshark, behavioral capture      ← Module 03\n<span class=\"G\">Level 3</span>  Ghidra disassembly, rename, follow code flow              ← Module 03\n<span class=\"Y\">Level 4</span>  x64dbg debugging, breakpoints, memory inspection         ← Module 03\n<span class=\"Y\">Level 5</span>  <span class=\"H\">Packer recognition and generic OEP unpacking</span>           ← THIS MODULE\n<span class=\"Y\">Level 6</span>  <span class=\"H\">Anti-analysis detection and defeat</span>                      ← THIS MODULE\n<span class=\"Y\">Level 7</span>  <span class=\"H\">Shellcode extraction and analysis from scratch</span>          ← THIS MODULE\n<span class=\"R\">Level 8</span>  <span class=\"H\">Obfuscation reversal: CFF, VM-based, metamorphic</span>        ← THIS MODULE\n<span class=\"R\">Level 9</span>  Custom packer and cryptor reverse engineering              ← Advanced/research\n<span class=\"R\">Level 10</span> Kernel-mode rootkit analysis, hypervisor RE              ← Specialist track</div>\n  </div>\n\n  <div class=\"g2\">\n    <div class=\"card cc\">\n      <div class=\"clabel\">Environment Requirements</div>\n      <div class=\"ctitle cyan\">ADDITIONAL TOOLS FOR THIS MODULE</div>\n      <div class=\"dtable-wrap\">\n        <table class=\"dtable\">\n          <tr><th>TOOL</th><th>PURPOSE</th></tr>\n          <tr><td><strong>ScyllaHide</strong></td><td>x64dbg plugin — defeats most anti-debug</td></tr>\n          <tr><td><strong>x64dbg + DBG</strong></td><td>Primary debugger for all dynamic work</td></tr>\n          <tr><td><strong>UniExtract / unipacker</strong></td><td>Automatic unpacker for common packers</td></tr>\n          <tr><td><strong>Scylla (IAT repair)</strong></td><td>Fix import table post-unpacking</td></tr>\n          <tr><td><strong>CFF Explorer</strong></td><td>PE header surgery and manual fixes</td></tr>\n          <tr><td><strong>hasherezade/pe-sieve</strong></td><td>Scan process memory for hollowing/injection</td></tr>\n          <tr><td><strong>libemu / sctest</strong></td><td>x86 shellcode emulation</td></tr>\n          <tr><td><strong>speakeasy</strong></td><td>Windows API emulation for shellcode</td></tr>\n          <tr><td><strong>de4dot</strong></td><td>.NET deobfuscator</td></tr>\n          <tr><td><strong>ILSpy / dnSpy</strong></td><td>.NET decompiler (better than Ghidra for .NET)</td></tr>\n        </table>\n      </div>\n    </div>\n    <div class=\"card\">\n      <div class=\"clabel\">Waveform — Analyst Workflow</div>\n      <div class=\"ctitle\">DETECTION-FIRST APPROACH</div>\n      <div class=\"cb\">\n<span class=\"C\"># Before spending hours in a debugger,</span>\n<span class=\"C\"># always ask: what do I actually need?</span>\n\n<span class=\"Y\">QUESTION 1:</span> Is it known?\n  sha256 → VirusTotal → family identified?\n  → If yes: read existing reports first\n\n<span class=\"Y\">QUESTION 2:</span> What do I need from it?\n  C2 IP/domain → strings/dynamic may suffice\n  Encryption key → need to debug decrypt routine\n  Full logic → full RE required\n\n<span class=\"Y\">QUESTION 3:</span> What layer am I on?\n  Entropy &gt; 7.0? → unpacking needed first\n  Anti-debug? → ScyllaHide first\n  Shellcode? → extract and emulate\n\n<span class=\"G\">Rule:</span> Use the minimum analysis depth needed.\n  Don't reverse-engineer what strings can answer.\n  Don't debug what Ghidra can answer.\n  Don't write custom unpackers when\n  unipacker handles it in 30 seconds.</div>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ═══════════════ PACKERS ═══════════════ -->\n<div class=\"module z1\" id=\"mod-packing\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-marker\">§1</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Packer Analysis //</div>\n      <div class=\"sh-title\">Packers, Cryptors & <span class=\"hl\">Protectors</span></div>\n      <div class=\"sh-desc\">Three categories of PE protection with escalating analysis difficulty. Recognizing which type you're facing determines the unpacking strategy.</div>\n    </div>\n  </div>\n\n  <!-- Packer taxonomy -->\n  <div class=\"g3\" style=\"margin-bottom:14px\">\n    <div class=\"card ca\">\n      <div class=\"clabel\">Type 01</div>\n      <div class=\"ctitle amber\">PACKERS</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">Compress the PE payload. Small stub decompresses at runtime. Entropy 6.5–7.5. Usually a single compression algorithm (LZMA, ZLIB, aPLib). OEP method works cleanly.</div>\n      <div class=\"cb\" style=\"font-size:.66rem\">\n<span class=\"C\"># Common packers:</span>\n<span class=\"Y\">UPX</span>    → trivial: <span class=\"G\">upx -d sample.exe</span>\n<span class=\"Y\">MPRESS</span> → signature: PE section \".MPRESS1\"\n<span class=\"Y\">aPLib</span>  → aPack packer (aPlib decompression)\n<span class=\"Y\">NSIS</span>   → Nullsoft installer wrapper\n\n<span class=\"C\"># Detection (Detect-It-Easy):</span>\n<span class=\"G\">die</span> sample.exe\n<span class=\"C\"># Shows: \"UPX 3.96 [LZMA, NRV2B]\"</span>\n<span class=\"C\"># Or: \"Packer: MPRESS 2.19\"</span></div>\n    </div>\n    <div class=\"card ca\">\n      <div class=\"clabel\">Type 02</div>\n      <div class=\"ctitle amber\">CRYPTORS</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">Encrypt the payload (XOR, RC4, AES, custom). Decryption key may be hardcoded, derived from system info, or fetched from C2. Entropy 7.0–8.0. OEP method works but you need the decrypted memory.</div>\n      <div class=\"cb\" style=\"font-size:.66rem\">\n<span class=\"C\"># XOR cryptor (simplest):</span>\n<span class=\"K\">for</span> i <span class=\"K\">in</span> range(len(encrypted)):\n    plain[i] = encrypted[i] ^ key[i % len(key)]\n\n<span class=\"C\"># Finding the key in x64dbg:</span>\n<span class=\"N\">1.</span> BP on decryption loop (high RIP activity)\n<span class=\"N\">2.</span> Inspect ECX/RCX (key byte) at XOR instruction\n<span class=\"N\">3.</span> Run until loop completes\n<span class=\"N\">4.</span> Dump decrypted region</div>\n    </div>\n    <div class=\"card ca\">\n      <div class=\"clabel\">Type 03</div>\n      <div class=\"ctitle amber\">PROTECTORS</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">Commercial protection (Themida, VMProtect, Obsidium). Add anti-debug, anti-VM, code virtualization, import obfuscation. OEP method harder — often virtualized. May require specialized tools.</div>\n      <div class=\"cb\" style=\"font-size:.66nm\">\n<span class=\"C\"># VMProtect — converts code to VM bytecode:</span>\n<span class=\"R\">Original x86:</span>\n  PUSH EAX\n  ADD EAX, 4\n  RET\n\n<span class=\"R\">VMProtect equivalent:</span>\n  CALL vm_entry          <span class=\"C\">← enters VM</span>\n  DB 0x3A, 0x1C, 0x08   <span class=\"C\">← custom bytecodes</span>\n  DB 0x07, 0x2F, 0xB4   <span class=\"C\">← VM interpreter</span>\n  <span class=\"C\">                           reads these</span>\n<span class=\"C\"># Must either: emulate the VM, or</span>\n<span class=\"C\"># trace execution and reconstruct logic</span></div>\n    </div>\n  </div>\n\n  <!-- PE structure of packed file -->\n  <div class=\"card ca\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Packed PE Anatomy</div>\n    <div class=\"ctitle amber\">READING THE PE HEADER OF A PACKED SAMPLE</div>\n    <div class=\"g2\">\n      <div>\n        <p class=\"cbody\" style=\"margin-bottom:10px\">A packed PE has a characteristic structure that distinguishes it from a clean binary. Learn to read these signals immediately:</p>\n        <div class=\"cb\">\n<span class=\"C\"># pefile analysis of packed sample</span>\n<span class=\"K\">import</span> pefile\n\npe = pefile.PE(<span class=\"S\">\"packed.exe\"</span>)\n\n<span class=\"C\"># Signal 1: Few or no imports</span>\n<span class=\"K\">for</span> e <span class=\"K\">in</span> getattr(pe, <span class=\"S\">\"DIRECTORY_ENTRY_IMPORT\"</span>, []):\n    <span class=\"F\">print</span>(e.dll.decode())\n<span class=\"C\"># Legitimate PE: 10+ DLLs</span>\n<span class=\"C\"># Packed PE: only kernel32.dll + LoadLibraryA</span>\n<span class=\"C\"># (just enough to bootstrap decompression)</span>\n\n<span class=\"C\"># Signal 2: Small .text, large unknown section</span>\n<span class=\"K\">for</span> s <span class=\"K\">in</span> pe.sections:\n    name = s.Name.decode().strip(<span class=\"S\">'\\x00'</span>)\n    e = s.get_entropy()\n    <span class=\"F\">print</span>(f<span class=\"S\">\"{name}: entropy={e:.2f}\"</span>)\n<span class=\"C\"># UPX: .text entropy ~7.8 (compressed code)</span>\n<span class=\"C\"># UPX0/UPX1 sections instead of normal names</span>\n\n<span class=\"C\"># Signal 3: Entry point in unusual section</span>\nep = pe.OPTIONAL_HEADER.AddressOfEntryPoint\n<span class=\"K\">for</span> s <span class=\"K\">in</span> pe.sections:\n    <span class=\"K\">if</span> s.VirtualAddress &lt;= ep &lt; s.VirtualAddress + s.Misc_VirtualSize:\n        <span class=\"F\">print</span>(f<span class=\"S\">\"EP in section: {s.Name.decode()}\"</span>)\n<span class=\"C\"># Packed: EP in \".packed\", \".prot\", \"UPX1\"</span>\n<span class=\"C\"># Clean:  EP in \".text\"</span></div>\n      </div>\n      <div>\n        <div class=\"hexdump\">\n<span style=\"color:var(--phos3)\">PACKED PE — HEX VIEW AT EP:</span>\n\n<span class=\"hex-addr\">00413000:</span> <span class=\"hex-byte hl\">60</span> <span class=\"hex-byte\">BE</span> <span class=\"hex-byte\">00</span> <span class=\"hex-byte\">30</span> <span class=\"hex-byte\">41</span> <span class=\"hex-byte\">00</span> <span class=\"hex-byte\">8D</span> <span class=\"hex-byte\">BE</span> <span class=\"hex-ascii hl\">`....</span>\n<span class=\"hex-addr\">00413008:</span> <span class=\"hex-byte\">00</span> <span class=\"hex-byte\">E0</span> <span class=\"hex-byte\">FE</span> <span class=\"hex-byte\">FF</span> <span class=\"hex-byte\">57</span> <span class=\"hex-byte\">89</span> <span class=\"hex-byte\">E5</span> <span class=\"hex-byte\">8D</span> <span class=\"hex-ascii\">....W...</span>\n<span class=\"hex-addr\">00413010:</span> <span class=\"hex-byte\">9C</span> <span class=\"hex-byte\">24</span> <span class=\"hex-byte\">80</span> <span class=\"hex-byte\">C0</span> <span class=\"hex-byte\">FE</span> <span class=\"hex-byte\">FF</span> <span class=\"hex-byte\">57</span> <span class=\"hex-byte\">31</span> <span class=\"hex-ascii\">.$....W1</span>\n\n<span style=\"color:var(--amber)\">↑ 0x60 = PUSHAD (save all registers)</span>\n<span style=\"color:var(--amber)\">← Classic UPX stub signature</span>\n\n<span style=\"color:var(--phos3)\">CLEAN PE — HEX VIEW AT EP:</span>\n\n<span class=\"hex-addr\">00401000:</span> <span class=\"hex-byte cyan\">55</span> <span class=\"hex-byte\">8B</span> <span class=\"hex-byte\">EC</span> <span class=\"hex-byte\">83</span> <span class=\"hex-byte\">E4</span> <span class=\"hex-byte\">F0</span> <span class=\"hex-byte\">83</span> <span class=\"hex-byte\">EC</span> <span class=\"hex-ascii\">U......</span>\n<span class=\"hex-addr\">00401008:</span> <span class=\"hex-byte\">18</span> <span class=\"hex-byte\">A1</span> <span class=\"hex-byte\">00</span> <span class=\"hex-byte\">30</span> <span class=\"hex-byte\">40</span> <span class=\"hex-byte\">00</span> <span class=\"hex-byte\">33</span> <span class=\"hex-byte\">C5</span> <span class=\"hex-ascii\">..0@.3.</span>\n\n<span style=\"color:var(--cyan2)\">↑ 0x55 = PUSH EBP (standard prologue)</span>\n<span style=\"color:var(--cyan2)\">← Standard function entry — no packer</span>\n        </div>\n        <div class=\"cb\" style=\"margin-top:8px;font-size:.66rem\">\n<span class=\"C\"># Detect-It-Easy (die) — fastest packer ID</span>\n<span class=\"G\">die</span> sample.exe\n\n<span class=\"C\"># Output examples:</span>\n<span class=\"H\">PE32: Packer: UPX(3.95)[NRV2B,best]</span>\n<span class=\"H\">PE32: Packer: Themida(3.1.x.x)[-]</span>\n<span class=\"H\">PE32: Compiler: MSVC(19.xx)</span>  <span class=\"C\">← clean</span></div>\n      </div>\n    </div>\n  </div>\n\n  <!-- Generic unpacking method -->\n  <div class=\"card\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Universal Technique</div>\n    <div class=\"ctitle\">GENERIC OEP UNPACKING — WORKS ON 80% OF PACKERS</div>\n    <div class=\"cb\">\n<span class=\"tag\">x64dbg</span>\n<span class=\"C\">################################################################################</span>\n<span class=\"C\"># THE GENERIC OEP METHOD — works when packer writes payload then jumps to it</span>\n<span class=\"C\">################################################################################</span>\n\n<span class=\"Y\">STEP 1: Open packed binary in x64dbg</span>\n  File → Open → packed.exe\n  <span class=\"C\"># Note: entry point is in packer stub, not real code</span>\n\n<span class=\"Y\">STEP 2: Install ScyllaHide plugin</span>\n  Plugins → ScyllaHide → Options → Profile → \"Maximum\"\n  <span class=\"C\"># Defeats: IsDebuggerPresent, timing checks, exceptions</span>\n\n<span class=\"Y\">STEP 3: Set memory breakpoint on execution</span>\n  Method A: Memory Map (Alt+M)\n    → Find section with EP → right-click → Set hardware BP on execution\n  Method B: VirtualAlloc/VirtualProtect hook\n    → When packer allocates new RWX memory → BP fires when payload executes\n\n<span class=\"Y\">STEP 4: Run (F9)</span>\n  Packer stub executes:\n    Allocates new memory region\n    Decompresses/decrypts original PE into it\n    Fixes up import table\n    Jumps to REAL entry point (OEP)\n  <span class=\"C\"># Your memory BP fires at the OEP</span>\n  <span class=\"C\"># Disassembly now shows normal-looking code (PUSH EBP etc.)</span>\n\n<span class=\"Y\">STEP 5: Verify you're at OEP</span>\n  EIP/RIP = address in new memory region\n  First instruction looks like normal compiler prologue:\n    PUSH EBP / MOV EBP, ESP / SUB ESP, XX  ← you're at OEP\n\n<span class=\"Y\">STEP 6: Dump with Scylla</span>\n  Plugins → Scylla → Dump\n  <span class=\"C\"># Creates unpacked PE on disk (import table still broken)</span>\n\n<span class=\"Y\">STEP 7: Fix imports with Scylla</span>\n  Scylla → IAT Autosearch\n  Scylla → Get Imports\n  Scylla → Fix Dump → select the dumped file\n  <span class=\"C\"># Now you have a fully working, importable PE</span>\n\n<span class=\"Y\">STEP 8: Verify in Ghidra</span>\n  Import fixed dump\n  Entropy should now be ~6.0-6.5 (normal code)\n  Full import table visible\n  Decompiler produces readable pseudoC</div>\n  </div>\n\n  <!-- UPX specific -->\n  <div class=\"g2\">\n    <div class=\"card ca\">\n      <div class=\"clabel\">UPX — Trivial Case</div>\n      <div class=\"ctitle amber\">UPX AUTO-UNPACK</div>\n      <div class=\"cb\">\n<span class=\"C\"># If not modified — just use upx tool</span>\n<span class=\"G\">upx</span> -d packed_sample.exe -o unpacked.exe\n\n<span class=\"C\"># Verify:</span>\n<span class=\"G\">die</span> unpacked.exe\n<span class=\"C\"># Should now show compiler (MSVC, GCC) not packer</span>\n\n<span class=\"C\"># If UPX is modified (header patched to break upx -d):</span>\n<span class=\"C\"># UPX signature bytes overwritten but stub code intact</span>\n<span class=\"C\"># Manual approach:</span>\n<span class=\"N\">1.</span> Open in x64dbg\n<span class=\"N\">2.</span> PUSHAD at start (0x60) → BP on POPAD (0x61)\n<span class=\"N\">3.</span> Run → lands at OEP after POPAD + JMP\n<span class=\"N\">4.</span> Use Scylla to dump + fix imports\n<span class=\"C\"># Or: fix UPX header, then upx -d works again</span>\n<span class=\"C\"># Header fix: write \"UPX!\" at correct offset</span></div>\n    </div>\n    <div class=\"card ca\">\n      <div class=\"clabel\">Automated — Try First</div>\n      <div class=\"ctitle amber\">UNIPACKER — AUTO UNPACK</div>\n      <div class=\"cb\">\n<span class=\"C\"># unipacker supports: UPX, ASPack, PEtite,</span>\n<span class=\"C\"># FSG, MPRESS, YZPack, and many more</span>\n\n<span class=\"G\">pip3</span> install unipacker\n\n<span class=\"C\"># Unpack automatically:</span>\n<span class=\"G\">unipacker</span> sample.exe\n\n<span class=\"C\"># Specify output:</span>\n<span class=\"G\">unipacker</span> -o unpacked/ sample.exe\n\n<span class=\"C\"># If unipacker fails:</span>\n<span class=\"C\"># → Try manual OEP method in x64dbg</span>\n<span class=\"C\"># → Check if it's a commercial protector</span>\n<span class=\"C\">     (Themida/VMProtect — no auto tool)</span>\n\n<span class=\"C\"># pe-sieve — scan process for unpacked PE:</span>\n<span class=\"G\">pe-sieve</span> /pid &lt;malware_pid&gt; /out dump/\n<span class=\"C\"># Scans and dumps all mapped PEs from process</span>\n<span class=\"C\"># Works while malware is running</span></div>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ═══════════════ ANTI-ANALYSIS ═══════════════ -->\n<div class=\"module z1\" id=\"mod-antianalysis\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-marker\">§2</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Evasion Chains //</div>\n      <div class=\"sh-title\">Anti-Analysis: <span class=\"hl\">Detection & Defeat</span></div>\n      <div class=\"sh-desc\">Malware authors invest heavily in making analysis painful. This section catalogs every significant anti-analysis technique with its exact implementation signature and the specific bypass for each.</div>\n    </div>\n  </div>\n\n  <div class=\"itabs\">\n    <button class=\"itab active\" onclick=\"iTab('ad',this)\">Anti-Debug</button>\n    <button class=\"itab\" onclick=\"iTab('avm',this)\">Anti-VM</button>\n    <button class=\"itab\" onclick=\"iTab('asb',this)\">Anti-Sandbox</button>\n    <button class=\"itab\" onclick=\"iTab('timing',this)\">Timing Attacks</button>\n  </div>\n\n  <div class=\"ipanel active\" id=\"ip-ad\">\n    <div class=\"g2\" style=\"margin-bottom:12px\">\n      <div class=\"card cr\">\n        <div class=\"clabel\">Anti-Debug 01</div>\n        <div class=\"ctitle red\">IsDebuggerPresent / CheckRemoteDebuggerPresent</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># Reads PEB.BeingDebugged flag (offset 0x2)</span>\n<span class=\"C\"># Returns 1 if debugger attached</span>\n\n<span class=\"C\"># Malware code (conceptual):</span>\n<span class=\"K\">if</span> IsDebuggerPresent() != <span class=\"N\">0</span>:\n    <span class=\"F\">ExitProcess</span>(<span class=\"N\">0</span>)  <span class=\"C\"># silently die</span>\n\n<span class=\"C\"># Assembly equivalent:</span>\n<span class=\"F\">CALL</span>  IsDebuggerPresent\n<span class=\"F\">TEST</span>  EAX, EAX\n<span class=\"F\">JNZ</span>   exit_routine    <span class=\"C\">← jump if debugger</span>\n\n<span class=\"R\">BYPASS OPTIONS:</span>\n<span class=\"G\">1.</span> ScyllaHide plugin → hooks return value → always 0\n<span class=\"G\">2.</span> Manual: find the CALL, patch JNZ → JZ (flip branch)\n<span class=\"G\">3.</span> Manual: find PEB.BeingDebugged → write 0 at offset 2\n   x64dbg: Ctrl+G → fs:[30]+2 → write 0x00\n<span class=\"G\">4.</span> Use Scylla anti-debug profile in x64dbg</span></div>\n      </div>\n      <div class=\"card cr\">\n        <div class=\"clabel\">Anti-Debug 02</div>\n        <div class=\"ctitle red\">NtQueryInformationProcess</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># Queries debug port — more stealthy than IsDebuggerPresent</span>\n<span class=\"C\"># ProcessInformationClass = 7 (ProcessDebugPort)</span>\n<span class=\"C\"># Returns non-zero if debugger attached</span>\n\n<span class=\"C\"># Often used as secondary check after IsDebuggerPresent</span>\n<span class=\"C\"># because more sophisticated malware assumes analysts</span>\n<span class=\"C\"># patch the first check</span>\n\n<span class=\"R\">BYPASS:</span>\n<span class=\"G\">1.</span> ScyllaHide hooks NtQueryInformationProcess\n   → returns 0 for ProcessDebugPort query\n<span class=\"G\">2.</span> Manual: BP on NtQueryInformationProcess\n   → after call, inspect return buffer\n   → if ProcessInformationClass==7, patch buffer to 0\n<span class=\"G\">3.</span> x64dbg: set conditional BP:\n   COND: [esp+8] == 7  (ProcessDebugPort param)\n   ACTION: EAX = 0 after return</div>\n      </div>\n    </div>\n    <div class=\"g2\" style=\"margin-bottom:12px\">\n      <div class=\"card cr\">\n        <div class=\"clabel\">Anti-Debug 03</div>\n        <div class=\"ctitle red\">OutputDebugString / CloseHandle Tricks</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># OutputDebugString trick:</span>\n<span class=\"C\"># Clears last error before call</span>\n<span class=\"C\"># If debugger attached: GetLastError() returns 0</span>\n<span class=\"C\"># If no debugger: GetLastError() returns non-zero</span>\n\nSetLastError(<span class=\"N\">0xDEAD</span>)\nOutputDebugString(<span class=\"S\">\"test\"</span>)\n<span class=\"K\">if</span> GetLastError() == <span class=\"N\">0</span>:\n    <span class=\"C\"># Debugger is present</span>\n\n<span class=\"C\"># CloseHandle trick:</span>\n<span class=\"C\"># Pass invalid handle to CloseHandle</span>\n<span class=\"C\"># Without debugger: exception, handled silently</span>\n<span class=\"C\"># With debugger: EXCEPTION_INVALID_HANDLE raised</span>\n<span class=\"C\">  and debugger may intercept it</span>\n\n<span class=\"R\">BYPASS:</span>\n<span class=\"G\">1.</span> ScyllaHide patches OutputDebugString behavior\n<span class=\"G\">2.</span> CloseHandle: set x64dbg to not break on that exception\n   Options → Exceptions → Add 0xC0000008\n   (INVALID_HANDLE exception code)</div>\n      </div>\n      <div class=\"card cr\">\n        <div class=\"clabel\">Anti-Debug 04</div>\n        <div class=\"ctitle red\">INT3 / Software Breakpoint Detection</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># Malware reads its own code looking for 0xCC (INT3)</span>\n<span class=\"C\"># Software breakpoints replace bytes with 0xCC</span>\n<span class=\"C\"># If any 0xCC found → debugger present</span>\n\n<span class=\"C\"># Malware implementation:</span>\ncrc32_start = &amp;check_function\ncrc32_end   = crc32_start + <span class=\"N\">100</span>\nexpected_crc = <span class=\"N\">0xDEADBEEF</span>   <span class=\"C\"># precomputed</span>\nactual_crc  = compute_crc32(crc32_start, <span class=\"N\">100</span>)\n<span class=\"K\">if</span> actual_crc != expected_crc:\n    <span class=\"C\"># Breakpoint or patching detected</span>\n\n<span class=\"R\">BYPASS:</span>\n<span class=\"G\">1.</span> Use HARDWARE breakpoints instead of software\n   (hardware BPs don't write 0xCC — use DR0-DR3)\n   x64dbg: right-click → Set Hardware BP → Execute\n<span class=\"G\">2.</span> NOP the CRC check: find the CMP+JNZ → NOP both\n<span class=\"G\">3.</span> Patch expected_crc to match modified code</div>\n      </div>\n    </div>\n    <!-- Assembly view of anti-debug bypass -->\n    <div class=\"card\">\n      <div class=\"clabel\">ScyllaHide — One-Click Defeat</div>\n      <div class=\"ctitle\">SCYLLAHIDE COVERAGE — WHAT IT AUTOMATICALLY PATCHES</div>\n      <div class=\"cb\">\n<span class=\"C\"># ScyllaHide patches ALL of these in x64dbg:</span>\n<span class=\"G\">✓</span> IsDebuggerPresent              → always returns 0\n<span class=\"G\">✓</span> CheckRemoteDebuggerPresent     → always returns FALSE\n<span class=\"G\">✓</span> NtQueryInformationProcess      → patched for debug port queries\n<span class=\"G\">✓</span> NtSetInformationThread         → ThreadHideFromDebugger\n<span class=\"G\">✓</span> NtQuerySystemInformation       → kernel debugger check\n<span class=\"G\">✓</span> GetTickCount / QueryPerf counter→ timing check defeat\n<span class=\"G\">✓</span> OutputDebugString              → patched\n<span class=\"G\">✓</span> FindWindow (OllyDbg detection) → returns NULL\n<span class=\"G\">✓</span> heap flags (PEB NtGlobalFlag)  → cleared\n<span class=\"G\">✓</span> Process heap (ForceFlags)      → cleared\n\n<span class=\"Y\">Install:</span>\n  x64dbg → Plugins → ScyllaHide\n  Available at: github.com/x64dbg/ScyllaHide\n  \n<span class=\"Y\">Usage:</span>\n  Plugins → ScyllaHide → Options\n  Select profile: \"Maximum\" for most malware\n  Load profile before starting debugger session</div>\n    </div>\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-avm\">\n    <div class=\"g2\" style=\"margin-bottom:12px\">\n      <div class=\"card cr\">\n        <div class=\"clabel\">Anti-VM 01</div>\n        <div class=\"ctitle red\">Registry Artifact Checks</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># Malware queries for VM-specific registry keys</span>\n<span class=\"C\"># If found → analysis environment detected</span>\n\n<span class=\"R\">VMware artifacts:</span>\n  HKLM\\SOFTWARE\\VMware, Inc.\\VMware Tools\n  HKLM\\SYSTEM\\CurrentControlSet\\Services\\vmhgfs\n  HKLM\\SYSTEM\\CurrentControlSet\\Services\\vmci\n\n<span class=\"R\">VirtualBox artifacts:</span>\n  HKLM\\SOFTWARE\\Oracle\\VirtualBox Guest Additions\n  HKLM\\SYSTEM\\CurrentControlSet\\Services\\VBoxSF\n  HKLM\\SYSTEM\\CurrentControlSet\\Services\\VBoxGuest\n\n<span class=\"G\">BYPASS:</span>\n  Delete these keys from registry (if snapshot ok)\n  Or: use bare-metal analysis machine\n  Or: patch the registry API call to return NOT_FOUND\n  Or: SysInternals Regshot → compare before/after key query</div>\n      </div>\n      <div class=\"card cr\">\n        <div class=\"clabel\">Anti-VM 02</div>\n        <div class=\"ctitle red\">Process & Driver Enumeration</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># Malware walks running processes looking for</span>\n<span class=\"C\"># VM tools, analysis tools, or security software</span>\n\n<span class=\"R\">VM tool processes to hide:</span>\n  vmtoolsd.exe    vmwaretray.exe\n  vmwareuser.exe  VBoxService.exe\n  VBoxTray.exe\n\n<span class=\"R\">Analysis tool processes to hide:</span>\n  procmon.exe     procexp.exe     autoruns.exe\n  wireshark.exe   x64dbg.exe      ghidra.exe\n  ida.exe         ollydbg.exe     fiddler.exe\n\n<span class=\"G\">BYPASS:</span>\n  Rename analysis tools:\n    x64dbg.exe → svchost32_dbg.exe\n    wireshark.exe → netmon_capture.exe\n  These names aren't in malware's block list\n  \n  Or: kill all VM tool processes before analysis\n  Or: patch the process enumeration loop → JMP past</div>\n      </div>\n    </div>\n    <div class=\"g2\">\n      <div class=\"card cr\">\n        <div class=\"clabel\">Anti-VM 03</div>\n        <div class=\"ctitle red\">CPUID Hypervisor Bit</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># CPUID with EAX=1 returns:</span>\n<span class=\"C\"># ECX bit 31 = hypervisor present flag</span>\n<span class=\"C\"># Set to 1 in VMs (VMware, VBox, Hyper-V)</span>\n\n<span class=\"C\"># Assembly check:</span>\n<span class=\"F\">MOV</span>  EAX, <span class=\"N\">1</span>\n<span class=\"F\">CPUID</span>\n<span class=\"F\">TEST</span> ECX, <span class=\"N\">80000000h</span>  <span class=\"C\">← bit 31</span>\n<span class=\"F\">JNZ</span>  vm_detected\n\n<span class=\"G\">BYPASS:</span>\n  x64dbg: set BP on CPUID instruction\n  After CPUID executes: clear bit 31 in ECX\n  ECX = ECX AND 0x7FFFFFFF  (clear bit 31)\n  \n  Or: VMware setting (some versions):\n  Add to .vmx: cpuid.1.ecx = \"default\"\n  \n  Or: bare metal analysis</div>\n      </div>\n      <div class=\"card cr\">\n        <div class=\"clabel\">Anti-VM 04</div>\n        <div class=\"ctitle red\">Hardware Artifact Checks</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># MAC address prefix check:</span>\n<span class=\"C\"># VMware: 00:0C:29, 00:50:56, 00:05:69</span>\n<span class=\"C\"># VirtualBox: 08:00:27</span>\n<span class=\"C\"># QEMU: 52:54:00</span>\n\n<span class=\"C\"># Hard disk model string:</span>\n<span class=\"C\"># \"VBOX HARDDISK\", \"VMware Virtual\", \"QEMU HARDDISK\"</span>\n\n<span class=\"C\"># Screen resolution check:</span>\n<span class=\"C\"># VMs often run at 800x600 or 1024x768</span>\n<span class=\"C\"># Humans rarely use 4:3 below 1080p</span>\n\n<span class=\"C\"># Memory size check:</span>\n<span class=\"C\"># VMs often have &lt;4GB RAM</span>\n<span class=\"C\"># Many sandbox VMs: exactly 1024MB or 2048MB</span>\n\n<span class=\"G\">BYPASS:</span>\n  Change VM MAC to vendor-like (random non-VM prefix)\n  Set VM RAM to 8GB+ (looks more real)\n  Set display to 1920x1080\n  Use a VM with custom disk model string</div>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-asb\">\n    <div class=\"g2\" style=\"margin-bottom:12px\">\n      <div class=\"card cr\">\n        <div class=\"clabel\">Anti-Sandbox 01</div>\n        <div class=\"ctitle red\">Sleep & Time Dilation</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># Sandboxes typically have a 3-5 minute timeout</span>\n<span class=\"C\"># Malware sleeps 10+ minutes → analysis window expires</span>\n<span class=\"C\"># Sandbox sees: no interesting behavior → clean</span>\n\n<span class=\"C\"># Common implementation:</span>\nSleep(<span class=\"N\">600000</span>)   <span class=\"C\"># 10 minutes</span>\n<span class=\"C\"># Or repeated short sleeps:</span>\n<span class=\"K\">for</span> i <span class=\"K\">in</span> range(<span class=\"N\">1000</span>):\n    Sleep(<span class=\"N\">1000</span>)   <span class=\"C\"># 1000 × 1s = 16.7 min</span>\n\n<span class=\"C\"># Time dilation detection:</span>\n<span class=\"C\"># Sandboxes compress sleep() calls to avoid timeouts</span>\n<span class=\"C\"># Malware: call Sleep(10000), check elapsed time</span>\n<span class=\"C\"># If elapsed &lt; 5000ms → time compression detected</span>\n\n<span class=\"G\">BYPASS (debugger):</span>\n  x64dbg: BP on Sleep()\n  Modify EAX (argument) → patch to 0 → instant return\n  Or: patch CALL Sleep → NOP NOP NOP NOP NOP\n  \n<span class=\"G\">Bypass (sandbox config):</span>\n  Configure Cuckoo: analysis_call_timeout\n  Use interactive sandbox (Any.run) → can interact manually</div>\n      </div>\n      <div class=\"card cr\">\n        <div class=\"clabel\">Anti-Sandbox 02</div>\n        <div class=\"ctitle red\">User Interaction Checks</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># Sandboxes don't move the mouse or type</span>\n<span class=\"C\"># Malware checks for human-like activity</span>\n\n<span class=\"C\"># Mouse movement check:</span>\npt1 = GetCursorPos()\nSleep(<span class=\"N\">5000</span>)\npt2 = GetCursorPos()\n<span class=\"K\">if</span> pt1 == pt2:\n    <span class=\"C\"># No mouse movement → sandbox</span>\n\n<span class=\"C\"># Click count check:</span>\n<span class=\"C\"># Count mouse clicks in last N seconds</span>\n<span class=\"C\"># Humans click frequently; sandboxes don't</span>\n\n<span class=\"C\"># Desktop foreground window:</span>\n<span class=\"C\"># Check if any window has focus recently</span>\n<span class=\"C\"># Sandboxes often have no focused window</span>\n\n<span class=\"G\">BYPASS (interactive sandbox):</span>\n  Use Any.run → move mouse, click around\n  \n<span class=\"G\">BYPASS (automated):</span>\n  Sandbox agent: pyautogui script moves mouse randomly\n  Or: patch GetCursorPos → return random coordinates\n  \n<span class=\"G\">BYPASS (debugger):</span>\n  Find the comparison → patch to always return \"human found\"\n  Condition: [pt1.x] != [pt2.x] → force non-equal</div>\n      </div>\n    </div>\n    <div class=\"card cr\">\n      <div class=\"clabel\">Anti-Sandbox 03</div>\n      <div class=\"ctitle red\">Environment & Context Checks</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># Sandboxes typically have:</span>\n<span class=\"C\"># - Few installed programs</span>\n<span class=\"C\"># - No browser history</span>\n<span class=\"C\"># - No recent documents</span>\n<span class=\"C\"># - Specific usernames (user, sandbox, maltest, cuckoo)</span>\n<span class=\"C\"># - Specific hostnames (SANDBOX, WIN7-ANALYSIS, etc.)</span>\n\n<span class=\"C\"># Real-world environment checks malware performs:</span>\n<span class=\"K\">if</span> GetUserName() <span class=\"K\">in</span> [<span class=\"S\">\"user\"</span>,<span class=\"S\">\"sandbox\"</span>,<span class=\"S\">\"maltest\"</span>,<span class=\"S\">\"cuckoo\"</span>]:\n    exit()\n\n<span class=\"K\">if</span> len(os.listdir(<span class=\"S\">\"C:/Program Files\"</span>)) &lt; <span class=\"N\">5</span>:\n    exit()  <span class=\"C\"># few installed programs</span>\n\n<span class=\"K\">if not</span> Path(<span class=\"S\">\"C:/Users/*/AppData/Local/Google/Chrome\"</span>).exists():\n    exit()  <span class=\"C\"># no browser installed</span>\n\n<span class=\"G\">BYPASS:</span>\n  Configure sandbox/VM with:\n  - Realistic username and hostname\n  - Installed Office, Chrome, Steam, etc.\n  - Populated browser history (FlareVM does this)\n  - Desktop shortcuts and recent documents</div>\n    </div>\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-timing\">\n    <div class=\"card cr\" style=\"margin-bottom:12px\">\n      <div class=\"clabel\">Timing Attacks — The Subtlest Defense</div>\n      <div class=\"ctitle red\">RDTSC / TIMING-BASED ANTI-DEBUG</div>\n      <div class=\"cbody\" style=\"margin-bottom:12px\">RDTSC (Read Time-Stamp Counter) reads the CPU cycle counter. The delta between two RDTSC calls reveals if code ran slowly — as it does under a debugger. This is extremely difficult to defeat without hardware breakpoints.</div>\n      <div class=\"g2\">\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># RDTSC timing check — assembly:</span>\n<span class=\"F\">RDTSC</span>                   <span class=\"C\">; read TSC → EDX:EAX</span>\n<span class=\"F\">MOV</span>  [saved_tsc], EAX   <span class=\"C\">; save low 32 bits</span>\n<span class=\"F\">CPUID</span>                   <span class=\"C\">; serializing fence</span>\n\n<span class=\"C\">; ... code to time ...</span>\n\n<span class=\"F\">RDTSC</span>                   <span class=\"C\">; read again</span>\n<span class=\"F\">SUB</span>  EAX, [saved_tsc]   <span class=\"C\">; delta</span>\n<span class=\"F\">CMP</span>  EAX, <span class=\"N\">0x100000</span>     <span class=\"C\">; threshold (~1M cycles)</span>\n<span class=\"F\">JA</span>   debugger_detected  <span class=\"C\">; too slow = debugger</span>\n\n<span class=\"C\"># With debugger: each breakpoint adds 10M+ cycles</span>\n<span class=\"C\"># Without debugger: 100-1000 cycles for same code</span></div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"G\">BYPASS STRATEGIES:</span>\n\n<span class=\"N\">1.</span> ScyllaHide patches RDTSC → returns fake value\n   Small consistent delta regardless of step time\n\n<span class=\"N\">2.</span> x64dbg: set RDTSC hook\n   Options → Engine → Try to fix RDTSC\n\n<span class=\"N\">3.</span> Hardware breakpoints instead of software\n   Hardware BPs don't stall CPU\n   Use x64dbg hardware BP: Ctrl+H\n\n<span class=\"N\">4.</span> NOP the comparison:\n   Find CMP EAX, [threshold]\n   Find subsequent JA/JNE → NOP it\n   Code jumps past the anti-debug exit\n\n<span class=\"N\">5.</span> Patch the threshold:\n   Find the comparison constant (0x100000)\n   Replace with 0xFFFFFFFF\n   Now threshold is impossibly high → never triggered\n\n<span class=\"Y\">NOTE:</span> QueryPerformanceCounter is similar —\nsame bypasses apply. ScyllaHide handles both.</div>\n      </div>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ═══════════════ SHELLCODE ═══════════════ -->\n<div class=\"module z1\" id=\"mod-shellcode\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-marker\">§3</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Position-Independent Code //</div>\n      <div class=\"sh-title\">Shellcode <span class=\"hl\">Analysis</span></div>\n      <div class=\"sh-desc\">Shellcode is position-independent code (PIC) with no import table. It must find Windows APIs at runtime by walking the PEB and hashing export names. Once you understand this pattern, all shellcode becomes readable.</div>\n    </div>\n  </div>\n\n  <!-- PEB walking -->\n  <div class=\"card cc\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Foundation — How Shellcode Finds APIs</div>\n    <div class=\"ctitle cyan\">THE PEB WALK — EVERY PIECE OF SHELLCODE USES THIS</div>\n    <div class=\"cbody\" style=\"margin-bottom:12px\">Shellcode has no import table. It must find kernel32.dll at runtime by walking the Process Environment Block (PEB) → InMemoryOrderModuleList → iterate DLLs → find kernel32 → walk its export table → find functions by name or hash.</div>\n    <div class=\"g2\">\n      <div class=\"cb\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"C\">; x86 PEB walk — the universal shellcode bootstrap</span>\n<span class=\"C\">; FS:[0x30] = PEB on x86 / GS:[0x60] on x64</span>\n\n<span class=\"F\">MOV</span>  EAX, <span class=\"F\">FS</span>:[<span class=\"N\">0x30</span>]          <span class=\"C\">; PEB pointer</span>\n<span class=\"F\">MOV</span>  EAX, [EAX + <span class=\"N\">0x0C</span>]        <span class=\"C\">; PEB.Ldr</span>\n<span class=\"F\">MOV</span>  ESI, [EAX + <span class=\"N\">0x14</span>]        <span class=\"C\">; InMemoryOrderModuleList.Flink</span>\n<span class=\"F\">LODSD</span>                           <span class=\"C\">; next module (ntdll)</span>\n<span class=\"F\">XCHG</span> EAX, ESI\n<span class=\"F\">LODSD</span>                           <span class=\"C\">; next module (kernel32)</span>\n<span class=\"F\">MOV</span>  EBX, [EAX + <span class=\"N\">0x10</span>]        <span class=\"C\">; kernel32 base address</span>\n\n<span class=\"C\">; Now walk kernel32 export table:</span>\n<span class=\"F\">MOV</span>  EDX, [EBX + <span class=\"N\">0x3C</span>]        <span class=\"C\">; PE header offset</span>\n<span class=\"F\">MOV</span>  EDX, [EBX + EDX + <span class=\"N\">0x78</span>]  <span class=\"C\">; export directory RVA</span>\n<span class=\"F\">ADD</span>  EDX, EBX                  <span class=\"C\">; export directory VA</span>\n<span class=\"F\">MOV</span>  ECX, [EDX + <span class=\"N\">0x18</span>]        <span class=\"C\">; number of functions</span>\n<span class=\"F\">MOV</span>  EAX, [EDX + <span class=\"N\">0x20</span>]        <span class=\"C\">; AddressOfNames RVA</span>\n<span class=\"F\">ADD</span>  EAX, EBX                  <span class=\"C\">; AddressOfNames VA</span>\n<span class=\"C\">; Now loop: hash each name → compare to target hash</span></div>\n      <div class=\"cb\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"C\"># Python: reproduce PEB walk for analysis</span>\n<span class=\"K\">import</span> pefile\n\n<span class=\"K\">def</span> <span class=\"F\">hash_name</span>(name: bytes) -> int:\n    <span class=\"S\">\"\"\"Ror13AddHash — most common shellcode hash\"\"\"</span>\n    h = <span class=\"N\">0</span>\n    <span class=\"K\">for</span> b <span class=\"K\">in</span> name:\n        h = ((h >> <span class=\"N\">13</span>) | (h << <span class=\"N\">19</span>)) & <span class=\"N\">0xFFFFFFFF</span>\n        h = (h + b) & <span class=\"N\">0xFFFFFFFF</span>\n    <span class=\"K\">return</span> h\n\n<span class=\"K\">def</span> <span class=\"F\">build_hash_table</span>(dll_path: str):\n    pe = pefile.PE(dll_path)\n    table = {}\n    <span class=\"K\">for</span> exp <span class=\"K\">in</span> pe.DIRECTORY_ENTRY_EXPORT.symbols:\n        <span class=\"K\">if</span> exp.name:\n            h = hash_name(exp.name + b<span class=\"S\">'\\x00'</span>)\n            table[h] = exp.name.decode()\n    <span class=\"K\">return</span> table\n\n<span class=\"C\"># Build table for kernel32.dll</span>\nkt = build_hash_table(<span class=\"S\">\"kernel32.dll\"</span>)\n\n<span class=\"C\"># Now: find mystery hash in shellcode, look up:</span>\nmystery_hash = <span class=\"N\">0xEC0E4E8E</span>   <span class=\"C\"># from shellcode</span>\n<span class=\"F\">print</span>(kt.get(mystery_hash))  <span class=\"C\"># → \"LoadLibraryA\"</span>\n\n<span class=\"C\"># Run against all common DLLs to resolve all hashes</span>\n<span class=\"K\">for</span> dll <span class=\"K\">in</span> [<span class=\"S\">\"kernel32\"</span>,<span class=\"S\">\"ntdll\"</span>,<span class=\"S\">\"ws2_32\"</span>,<span class=\"S\">\"wininet\"</span>]:\n    table = build_hash_table(f<span class=\"S\">\"C:/Windows/System32/{dll}.dll\"</span>)\n    <span class=\"K\">if</span> mystery_hash <span class=\"K\">in</span> table:\n        <span class=\"F\">print</span>(f<span class=\"S\">\"{dll}: {table[mystery_hash]}\"</span>)</div>\n    </div>\n  </div>\n\n  <!-- Shellcode extraction -->\n  <div class=\"g2\" style=\"margin-bottom:14px\">\n    <div class=\"card cc\">\n      <div class=\"clabel\">Extraction Methods</div>\n      <div class=\"ctitle cyan\">EXTRACTING SHELLCODE FROM VARIOUS SOURCES</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"C\"># From memory dump (Volatility malfind output):</span>\n<span class=\"G\">vol</span> -f mem.dmp windows.malfind --dump\n<span class=\"C\"># Saves suspected shellcode as .dmp files</span>\n<span class=\"C\"># Check for non-MZ headers → raw shellcode (no PE)</span>\n\n<span class=\"C\"># From network PCAP (encoded payload):</span>\n<span class=\"G\">tshark</span> -r capture.pcap -Y \"http.request.method==POST\" \\\n    -T fields -e http.file_data > b64_payload.txt\n<span class=\"G\">base64</span> -d b64_payload.txt > raw_shellcode.bin\n<span class=\"G\">file</span> raw_shellcode.bin  <span class=\"C\"># PE or raw shellcode?</span>\n\n<span class=\"C\"># From document macro (VBA encoded payload):</span>\n<span class=\"C\"># Find: CreateObject(\"WScript.Shell\")</span>\n<span class=\"C\"># Extract the base64/hex blob after it</span>\n<span class=\"G\">python3</span> -c <span class=\"S\">\"\nimport base64, re, sys\ndata = open(sys.argv[1]).read()\nblobs = re.findall(r'[A-Za-z0-9+/=]{100,}', data)\nfor i,b in enumerate(blobs):\n    try:\n        open(f'blob_{i}.bin','wb').write(base64.b64decode(b))\n    except: pass\n\"</span> macro.vba\n\n<span class=\"C\"># From PE resource section:</span>\n<span class=\"G\">python3</span> -c <span class=\"S\">\"\nimport pefile\npe = pefile.PE('dropper.exe')\nfor res in pe.DIRECTORY_ENTRY_RESOURCE.entries:\n    for entry in res.directory.entries:\n        data = pe.get_data(entry.directory.entries[0].data.struct.OffsetToData,\n                           entry.directory.entries[0].data.struct.Size)\n        open(f'resource_{res.name}.bin','wb').write(data)\n\"</span></div>\n    </div>\n\n    <div class=\"card cc\">\n      <div class=\"clabel\">Analysis Methods</div>\n      <div class=\"ctitle cyan\">EMULATE & DISASSEMBLE SHELLCODE</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"C\"># Method 1: libemu / sctest (x86 emulation)</span>\n<span class=\"G\">sctest</span> -Ss 100000 -i shellcode.bin -G shell_trace.dot\ndot -Tpng shell_trace.dot > shellcode_flow.png\n\n<span class=\"C\"># Method 2: speakeasy — Windows API emulation</span>\n<span class=\"G\">speakeasy</span> -t shellcode.bin -r -a x86\n<span class=\"C\"># Shows: Windows API calls without actually running</span>\n<span class=\"C\"># Output: CreateProcess(\"cmd.exe\"), WSAConnect(...)\n\n# Method 3: Disassemble with ndisasm / objdump</span>\n<span class=\"G\">ndisasm</span> -b 32 shellcode.bin | head -100\n<span class=\"G\">objdump</span> -D -b binary -m i386 shellcode.bin | head -50\n\n<span class=\"C\"># Method 4: Load into Ghidra as raw bytes</span>\n<span class=\"C\"># File → Import File → Language: x86:LE:32:default</span>\n<span class=\"C\"># Format: Raw Binary</span>\n<span class=\"C\"># Analyze → disassembly + decompiler works on raw shellcode</span>\n\n<span class=\"C\"># Method 5: Execute safely in harness (x64dbg)</span>\n<span class=\"C\"># Inject shellcode into a dummy process:</span>\n<span class=\"G\">python3</span> -c <span class=\"S\">\"\nimport ctypes, sys\nsc = open(sys.argv[1],'rb').read()\nbuf = ctypes.create_string_buffer(sc)\nptr = ctypes.cast(buf, ctypes.c_void_p)\nctypes.windll.kernel32.VirtualProtect(ptr, len(sc), 0x40, ctypes.byref(ctypes.c_ulong(0)))\nfunc = ctypes.cast(ptr, ctypes.CFUNCTYPE(None))\n# DO NOT call func() without a debugger attached\nprint(f'Shellcode at: {ptr.value:#x} — attach debugger now')\ninput('Press Enter after attaching...')\nfunc()\n\"</span> shellcode.bin</div>\n    </div>\n  </div>\n\n  <!-- Common shellcode patterns -->\n  <div class=\"card\">\n    <div class=\"clabel\">Pattern Library</div>\n    <div class=\"ctitle\">RECOGNIZING COMMON SHELLCODE PATTERNS AT A GLANCE</div>\n    <div class=\"cb\">\n<span class=\"C\">###############################################################################</span>\n<span class=\"C\"># PATTERN 1: GetPC (Get-Program-Counter) — shellcode finding its own location</span>\n<span class=\"C\">###############################################################################</span>\n<span class=\"C\"># Common x86 pattern:</span>\n<span class=\"F\">CALL</span> next_instruction      <span class=\"C\">; CALL pushes EIP onto stack</span>\nnext_instruction:\n<span class=\"F\">POP</span>  EBX                   <span class=\"C\">; EBX = address of this instruction</span>\n<span class=\"C\"># Now shellcode knows its own base address — adds offsets to find strings/code</span>\n\n<span class=\"C\">###############################################################################</span>\n<span class=\"C\"># PATTERN 2: Socket / Reverse Shell setup</span>\n<span class=\"C\">###############################################################################</span>\n<span class=\"C\"># After PEB walk finds ws2_32.dll:</span>\n<span class=\"F\">PUSH</span> <span class=\"N\">0x0100007F</span>            <span class=\"C\">; 127.0.0.1 (reverse — note byte order)</span>\n<span class=\"F\">PUSH</span> <span class=\"N\">0x5C11</span>                <span class=\"C\">; port 4444 (0x115C little-endian)</span>\n<span class=\"F\">PUSH</span> <span class=\"N\">0x0002</span>                <span class=\"C\">; AF_INET</span>\n<span class=\"F\">PUSH</span> ESP                   <span class=\"C\">; sockaddr structure</span>\n<span class=\"F\">PUSH</span> <span class=\"N\">0x10</span>                  <span class=\"C\">; sizeof(sockaddr)</span>\n<span class=\"F\">PUSH</span> EDI                   <span class=\"C\">; socket handle</span>\n<span class=\"F\">CALL</span> [WSAConnect]          <span class=\"C\">; connect to attacker</span>\n<span class=\"C\"># IP 127.0.0.1 in little-endian: 7F 00 00 01 stored as 0x0100007F</span>\n\n<span class=\"C\">###############################################################################</span>\n<span class=\"C\"># PATTERN 3: EXITFUNC — cleanup options at end of shellcode</span>\n<span class=\"C\">###############################################################################</span>\n<span class=\"C\"># Metasploit shellcode EXITFUNC options:</span>\n<span class=\"K\">none</span>:    just jump to next instruction (risky — crashes)\n<span class=\"K\">process</span>: ExitProcess(0)  — clean exit\n<span class=\"K\">thread</span>:  ExitThread(0)   — cleaner, process keeps running\n<span class=\"K\">seh</span>:     structured exception handler — stealthiest\n\n<span class=\"C\">###############################################################################</span>\n<span class=\"C\"># PATTERN 4: Egg hunter — find payload in memory</span>\n<span class=\"C\">###############################################################################</span>\n<span class=\"C\"># Small first-stage shellcode searches memory for an \"egg\" marker</span>\n<span class=\"C\"># Egg = 4-8 byte unique value prepended to real payload</span>\n<span class=\"F\">MOV</span>  EDX, <span class=\"N\">0xFFFF0000</span>      <span class=\"C\">; start address</span>\nnext_page:\n<span class=\"F\">MOV</span>  EDX, EDX + <span class=\"N\">0x1000</span>   <span class=\"C\">; next page</span>\n<span class=\"C\">; check if page readable (NtAccessCheckAndAuditAlarm)</span>\n<span class=\"F\">MOV</span>  EAX, <span class=\"N\">0x50905090</span>     <span class=\"C\">; egg value</span>\n<span class=\"F\">SCASD</span>                      <span class=\"C\">; compare [EDI] to EAX</span>\n<span class=\"F\">JNZ</span>  next_page\n<span class=\"F\">SCASD</span>                      <span class=\"C\">; second egg check (avoid false positives)</span>\n<span class=\"F\">JNZ</span>  next_page\n<span class=\"F\">JMP</span>  EDI                   <span class=\"C\">; found egg → jump to payload</span></div>\n  </div>\n\n</div>\n</div>\n\n<!-- ═══════════════ OBFUSCATION ═══════════════ -->\n<div class=\"module z1\" id=\"mod-obfuscation\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-marker\">§4</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Code Obfuscation //</div>\n      <div class=\"sh-title\">Obfuscation <span class=\"hl\">Patterns & Reversal</span></div>\n      <div class=\"sh-desc\">String encryption, control flow flattening, opaque predicates, metamorphic code — each technique obscures meaning at a different level. This section covers recognition, tooling, and manual reversal strategies.</div>\n    </div>\n  </div>\n\n  <div class=\"itabs\">\n    <button class=\"itab active\" onclick=\"iTab('str',this)\">String Encryption</button>\n    <button class=\"itab\" onclick=\"iTab('cff',this)\">Control Flow Flattening</button>\n    <button class=\"itab\" onclick=\"iTab('poly',this)\">Polymorphic / Metamorphic</button>\n    <button class=\"itab\" onclick=\"iTab('dotnet',this)\">.NET Obfuscation</button>\n  </div>\n\n  <div class=\"ipanel active\" id=\"ip-str\">\n    <div class=\"g2\" style=\"margin-bottom:12px\">\n      <div class=\"card\">\n        <div class=\"clabel\">Most Common Technique</div>\n        <div class=\"ctitle\">XOR STRING ENCRYPTION — RECOGNITION & REVERSAL</div>\n        <div class=\"cb\">\n<span class=\"C\"># Ghidra: recognize XOR string decrypt loop</span>\n<span class=\"C\"># Pattern: loop + XOR instruction + counter + array write</span>\n\n<span class=\"C\"># Decompiler shows something like:</span>\nlocal_buf[<span class=\"N\">0</span>] = <span class=\"N\">0x48</span> ^ <span class=\"N\">0x25</span>;  <span class=\"C\"># → 0x6D → 'm'</span>\nlocal_buf[<span class=\"N\">1</span>] = <span class=\"N\">0x71</span> ^ <span class=\"N\">0x25</span>;  <span class=\"C\"># → 0x54 → 'T'</span>\n<span class=\"C\"># Or loop form with key byte at [key_array + i%len]</span>\n\n<span class=\"C\"># REVERSAL METHOD 1: x64dbg breakpoint at end of loop</span>\n<span class=\"N\">1.</span> Find the decrypt function in Ghidra\n<span class=\"N\">2.</span> Note the address of instruction AFTER the XOR loop\n<span class=\"N\">3.</span> In x64dbg: BP at that address\n<span class=\"N\">4.</span> Run → function decrypts → BP fires\n<span class=\"N\">5.</span> Inspect memory at result buffer (register points there)\n<span class=\"N\">6.</span> String is now decrypted — copy it out\n\n<span class=\"C\"># REVERSAL METHOD 2: Ghidra scripting</span>\n<span class=\"G\">python3</span> -c <span class=\"S\">\"\nencrypted = bytes.fromhex('486f77617265596f75')\nkey = bytes.fromhex('25')  # single byte key\nresult = bytes(b ^ key[i % len(key)] for i,b in enumerate(encrypted))\nprint(result.decode())\n\"</span>\n<span class=\"C\"># → 'mBr|TjZc\\\\'</span>\n\n<span class=\"C\"># REVERSAL METHOD 3: Ghidra EmulatorHelper script</span>\n<span class=\"C\"># Emulate just the decrypt function in Ghidra</span>\n<span class=\"C\"># Returns decrypted buffer without running malware</span></div>\n      </div>\n      <div class=\"card\">\n        <div class=\"clabel\">More Sophisticated</div>\n        <div class=\"ctitle\">AES / RC4 STRING DECRYPTION</div>\n        <div class=\"cb\">\n<span class=\"C\"># Modern malware uses AES-256 or RC4 for string encryption</span>\n<span class=\"C\"># KEY INSIGHT: key is hardcoded somewhere in binary</span>\n\n<span class=\"C\"># Finding the key:</span>\n<span class=\"N\">1.</span> Find the decryption routine (CryptDecrypt, AES rounds)\n<span class=\"N\">2.</span> Set BP on first call to it\n<span class=\"N\">3.</span> Arguments include: pointer to key, key length, ciphertext\n<span class=\"N\">4.</span> Inspect stack: [ESP+8] or RDX might be the key pointer\n<span class=\"N\">5.</span> Dump 32 bytes at that address = AES-256 key\n\n<span class=\"C\"># RC4 recognition in Ghidra:</span>\n<span class=\"C\"># KSA (Key Scheduling Algorithm):</span>\n<span class=\"C\"># Loop 0-255 initializing array: S[i] = i</span>\n<span class=\"C\"># Then swap loop mixing in key bytes</span>\n<span class=\"C\"># PRGA (Pseudo-Random Generation):</span>\n<span class=\"C\"># Generates XOR keystream</span>\n\n<span class=\"C\"># Extract key and decrypt offline:</span>\n<span class=\"G\">python3</span> -c <span class=\"S\">\"\nfrom Crypto.Cipher import ARC4\n\nkey = bytes.fromhex('01234567890abcdef01234567890abcdef01234567890abcdef01234567890')  # from dump\nciphertext = bytes.fromhex('deadbeef...')  # from binary\ncipher = ARC4.new(key)\nprint(cipher.decrypt(ciphertext))\n\"</span></div>\n      </div>\n    </div>\n    <div class=\"card\">\n      <div class=\"clabel\">Advanced Tool</div>\n      <div class=\"ctitle\">FLOSS — AUTOMATED STRING EXTRACTION</div>\n      <div class=\"cb\">\n<span class=\"C\"># FLOSS (FLARE Obfuscated String Solver) handles:</span>\n<span class=\"C\"># - Stack strings (built char by char)</span>\n<span class=\"C\"># - Tight loops (XOR/ADD decryption)</span>\n<span class=\"C\"># - Decoded strings (function-based decryption)</span>\n\n<span class=\"G\">floss</span> sample.exe                      <span class=\"C\"># all strings</span>\n<span class=\"G\">floss</span> sample.exe --only decoded        <span class=\"C\"># only decoded strings</span>\n<span class=\"G\">floss</span> sample.exe --no-static-strings   <span class=\"C\"># skip raw strings</span>\n<span class=\"G\">floss</span> sample.exe -o json > strings.json  <span class=\"C\"># machine-readable</span>\n\n<span class=\"C\"># FLOSS limitations:</span>\n<span class=\"C\"># - Cannot handle AES/RC4 (needs key from runtime)</span>\n<span class=\"C\"># - Misses C2-fetched strings (downloaded at runtime)</span>\n<span class=\"C\"># - Sometimes misidentifies constants as stack strings</span>\n<span class=\"C\"># Always review FLOSS output critically</span>\n\n<span class=\"C\"># HashDB plugin for Ghidra — resolve API hashes:</span>\n<span class=\"C\"># Install: github.com/OALabs/hashdb-ghidra</span>\n<span class=\"C\"># Right-click on hash constant → HashDB Lookup</span>\n<span class=\"C\"># Automatically identifies: ror13, djb2, fnv1a, crc32 etc.</span>\n<span class=\"C\"># Renames the constant to the API name in decompiler</span></div>\n    </div>\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-cff\">\n    <div class=\"card\" style=\"margin-bottom:12px\">\n      <div class=\"clabel\">Control Flow Flattening</div>\n      <div class=\"ctitle\">CFF — RECOGNITION & REVERSAL</div>\n      <div class=\"cbody\" style=\"margin-bottom:12px\">Control Flow Flattening (CFF) transforms structured code into a giant switch statement. All basic blocks are dispatched through a central dispatcher based on a state variable. The result looks like spaghetti code with no discernible structure — but it's reversible.</div>\n      <div class=\"g2\">\n        <div class=\"cb\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"C\">// ORIGINAL CODE (readable):</span>\n<span class=\"K\">if</span> (condition) {\n    block_A();\n} <span class=\"K\">else</span> {\n    block_B();\n}\nblock_C();\n\n<span class=\"C\">// AFTER CFF (obfuscated):</span>\nstate = <span class=\"N\">0x1234ABCD</span>;   <span class=\"C\">// initial state</span>\n<span class=\"K\">while</span> (true) {\n    <span class=\"K\">switch</span> (state) {\n        <span class=\"K\">case</span> <span class=\"N\">0x1234ABCD</span>: <span class=\"C\">// dispatcher check</span>\n            <span class=\"K\">if</span> (cond) state = <span class=\"N\">0x5678EF01</span>;\n            <span class=\"K\">else</span>      state = <span class=\"N\">0x9ABCDE23</span>;\n            <span class=\"K\">break</span>;\n        <span class=\"K\">case</span> <span class=\"N\">0x5678EF01</span>: block_A(); state = <span class=\"N\">0x4567AB89</span>; <span class=\"K\">break</span>;\n        <span class=\"K\">case</span> <span class=\"N\">0x9ABCDE23</span>: block_B(); state = <span class=\"N\">0x4567AB89</span>; <span class=\"K\">break</span>;\n        <span class=\"K\">case</span> <span class=\"N\">0x4567AB89</span>: block_C(); state = EXIT; <span class=\"K\">break</span>;\n    }\n}</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"G\">CFF Recognition signals in Ghidra:</span>\n  - Massive function with hundreds of basic blocks\n  - Central 'dispatcher' block with many outgoing edges\n  - Most blocks end with: [state_var] = constant; JMP dispatcher\n  - Condition blocks → update state, jump back to dispatcher\n\n<span class=\"G\">Reversal with D-810 (Ghidra plugin):</span>\n  github.com/jpenalbae/d810\n  Plugins → D-810 → Run all rules\n  Reconstructs original control flow automatically\n\n<span class=\"G\">Reversal with miasm (Python):</span>\n<span class=\"K\">from</span> miasm.analysis.machine <span class=\"K\">import</span> Machine\n<span class=\"K\">from</span> miasm.analysis.simplifier <span class=\"K\">import</span> IRCFGSimplifierCommon\n<span class=\"C\"># Symbolic execution follows all paths through dispatcher</span>\n<span class=\"C\"># Reconstructs true successors for each block</span>\n\n<span class=\"G\">Manual approach:</span>\n  1. Identify the state variable (written before every dispatcher call)\n  2. Trace: follow state 0x1234ABCD → find which case handles it\n  3. Build a map: state_value → block_function\n  4. Re-read code following the map, not the dispatcher</div>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-poly\">\n    <div class=\"g2\" style=\"margin-bottom:12px\">\n      <div class=\"card cr\">\n        <div class=\"clabel\">Polymorphic Engines</div>\n        <div class=\"ctitle red\">POLYMORPHIC CODE — SAME LOGIC, DIFFERENT BYTES</div>\n        <div class=\"cbody\" style=\"margin-bottom:10px\">Polymorphic malware mutates its own decryption stub on each infection while keeping the encrypted payload identical. The AV signature of the stub never matches twice.</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># Polymorphic engine strategy:</span>\n<span class=\"C\"># 1. Payload is encrypted with a random key each infection</span>\n<span class=\"C\"># 2. Decryption stub is REGENERATED with equivalent but</span>\n<span class=\"C\">#    different-looking code each time</span>\n\n<span class=\"C\"># SAME logic, different bytes (example):</span>\n<span class=\"C\"># Version 1:</span>\n<span class=\"H\">MOV EAX, [key]</span>\n<span class=\"H\">XOR [payload+ECX], AL</span>\n\n<span class=\"C\"># Version 2 (equivalent, different bytes):</span>\n<span class=\"H\">PUSH [key]</span>\n<span class=\"H\">POP EBX</span>\n<span class=\"H\">MOV EAX, EBX</span>\n<span class=\"H\">XOR [payload+ECX], AH</span>   <span class=\"C\">← uses AH instead of AL</span>\n\n<span class=\"C\"># Version 3:</span>\n<span class=\"H\">MOV EDX, [key]</span>\n<span class=\"H\">AND EDX, 0xFF</span>            <span class=\"C\">← equivalent to low byte</span>\n<span class=\"H\">XOR [payload+ECX], DL</span>\n\n<span class=\"G\">Analysis approach:</span>\n  Run through decryption loop in debugger\n  Dump decrypted payload after loop completes\n  Payload = same every time → analyze payload, not stub\n  YARA: target payload bytes, not stub bytes</div>\n      </div>\n      <div class=\"card cr\">\n        <div class=\"clabel\">Metamorphic Engines</div>\n        <div class=\"ctitle red\">METAMORPHIC CODE — LOGIC REWRITES ITSELF</div>\n        <div class=\"cbody\" style=\"margin-bottom:10px\">True metamorphism rewrites the ENTIRE binary — including the engine itself — using code transformations. This is the hardest class to detect with signatures.</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--red)\">\n<span class=\"C\"># Metamorphic transformations used:</span>\n<span class=\"N\">1.</span> Instruction substitution (equivalent instructions):\n   ADD EAX, 1  ←→  INC EAX\n   MOV EBX, 0  ←→  XOR EBX, EBX  ←→  SUB EBX, EBX\n\n<span class=\"N\">2.</span> Junk code insertion (never executes or affects state):\n   PUSH EAX / POP EAX  (save/restore same register)\n   MOV ECX, ECX        (no-op move)\n   XOR EAX, 0x00000000 (XOR with zero = no-op)\n\n<span class=\"N\">3.</span> Register reassignment:\n   Use EDI instead of ESI throughout\n   All references consistently renamed\n\n<span class=\"N\">4.</span> Code transposition (reorder independent blocks)\n<span class=\"N\">5.</span> Subroutine reordering (change function order in binary)\n\n<span class=\"G\">Analysis implications:</span>\n  Cannot rely on ANY byte-level signature\n  Must use: behavioral detection (what it DOES)\n  YARA: very hard — small invariant byte patterns only\n  ML: statistical features (entropy per section, etc.)\n  Best approach: sandbox execution → behavioral IOCs</div>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"ipanel\" id=\"ip-dotnet\">\n    <div class=\"g2\" style=\"margin-bottom:12px\">\n      <div class=\"card cc\">\n        <div class=\"clabel\">.NET Malware</div>\n        <div class=\"ctitle cyan\">.NET OBFUSCATION & DEOBFUSCATION</div>\n        <div class=\"cbody\" style=\"margin-bottom:10px\">.NET malware (AgentTesla, Formbook, AsyncRAT) ships in IL (Intermediate Language) bytecode — much easier to decompile than native code. But .NET obfuscators fight back.</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"C\"># Identify .NET binaries:</span>\n<span class=\"G\">file</span> sample.exe          <span class=\"C\"># \"PE32 executable (.NET)\"</span>\n<span class=\"G\">die</span> sample.exe           <span class=\"C\"># \"Linker: Microsoft Linker(48.0)[.NET]\"</span>\n\n<span class=\"C\"># Step 1: Try de4dot (automated deobfuscator)</span>\n<span class=\"G\">de4dot</span> sample.exe -o deobfuscated.exe\n<span class=\"C\"># Handles: ConfuserEx, Eazfuscator, SmartAssembly,</span>\n<span class=\"C\">#          .NET Reactor, Dotfuscator, Agile.NET</span>\n\n<span class=\"C\"># Step 2: Decompile with ILSpy / dnSpy</span>\n<span class=\"G\">ilspy</span> deobfuscated.exe\n<span class=\"C\"># Shows: full C# source code (clean methods, class names)</span>\n\n<span class=\"C\"># Step 3: If de4dot fails (custom obfuscation):</span>\n<span class=\"C\"># Use dnSpy to debug the .NET binary directly</span>\n<span class=\"C\"># Set breakpoints on suspicious methods</span>\n<span class=\"C\"># Much easier than native code debugging</span>\n\n<span class=\"C\"># Step 4: Resource/embedded payload extraction:</span>\n<span class=\"G\">python3</span> -c <span class=\"S\">\"\nimport dnfile  # pip install dnfile\ndn = dnfile.dnPE('sample.exe')\nfor r in dn.net.resources.rowlist:\n    name = r.Name\n    data = dn.net.resources.get_bytes(r)\n    open(f'resource_{name}.bin','wb').write(data)\n\"</span></div>\n      </div>\n      <div class=\"card cc\">\n        <div class=\"clabel\">Common .NET Obfuscation</div>\n        <div class=\"ctitle cyan\">ConfuserEx & Custom PATTERNS</div>\n        <div class=\"cb\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"C\"># ConfuserEx obfuscation techniques:</span>\n<span class=\"N\">1.</span> Symbol renaming: all methods/classes → AABBBCC type names\n<span class=\"N\">2.</span> Control flow obfuscation: similar to CFF\n<span class=\"N\">3.</span> Anti-tamper: CRC check on assembly at startup\n<span class=\"N\">4.</span> Anti-dump: patches memory to break dumping\n<span class=\"N\">5.</span> Constant encryption: string literals encrypted\n\n<span class=\"C\"># ConfuserEx custom obfuscated string decryption:</span>\n<span class=\"C\"># Strings stored as encrypted byte arrays in resource</span>\n<span class=\"C\"># Decryption happens in static constructor (.cctor)</span>\n\n<span class=\"C\"># Strategy: break on string decrypt method in dnSpy</span>\n<span class=\"C\"># Let strings decrypt themselves → inspect locals</span>\n\n<span class=\"C\"># AgentTesla specific (common RAT):</span>\n<span class=\"C\"># All strings are AES-256 encrypted</span>\n<span class=\"C\"># Key and IV are base64-encoded constants in .ctor</span>\n<span class=\"G\">python3</span> -c <span class=\"S\">\"\nfrom Crypto.Cipher import AES\nimport base64\nkey = base64.b64decode('FOUND_KEY_FROM_DNSPY')\niv  = base64.b64decode('FOUND_IV_FROM_DNSPY')\nct  = base64.b64decode('ENCRYPTED_STRING')\ncipher = AES.new(key, AES.MODE_CBC, iv)\nprint(cipher.decrypt(ct))\n\"</span></div>\n      </div>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ═══════════════ UNPACKING LAB ═══════════════ -->\n<div class=\"module z1\" id=\"mod-unpacking\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-marker\">§5</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Hands-On // </div>\n      <div class=\"sh-title\">Unpacking <span class=\"hl\">Lab Exercises</span></div>\n      <div class=\"sh-desc\">Three progressive unpacking exercises building from trivial (UPX) to intermediate (custom XOR cryptor) to challenging (multi-stage dropper with anti-debug). All require FlareVM + x64dbg + ScyllaHide.</div>\n    </div>\n  </div>\n\n  <div class=\"alert a-err\" style=\"margin-bottom:16px\"><strong>PREREQUISITES:</strong> FlareVM with x64dbg installed. ScyllaHide plugin installed. Snapshot taken (CLEAN_BASELINE). FakeNet-NG running. All samples from MalwareBazaar or CyberDefenders in isolated VM.</div>\n\n  <!-- Lab 1: UPX -->\n  <div class=\"card ca\" style=\"margin-bottom:12px\">\n    <div class=\"clabel\">Unpacking Lab 01 — Trivial</div>\n    <div class=\"ctitle amber\">MODIFIED UPX — THE CLASSIC STARTING POINT</div>\n    <div class=\"cbody\" style=\"margin-bottom:10px\"><strong>Scenario:</strong> Sample shows UPX sections (UPX0, UPX1) but <code>upx -d</code> fails because the UPX magic bytes were overwritten. You must manually unpack it in x64dbg.</div>\n    <div class=\"cb\">\n<span class=\"tag\">x64dbg — FlareVM</span>\n<span class=\"C\">## Step 1: Confirm it's modified UPX</span>\n<span class=\"G\">die</span> sample.exe\n<span class=\"C\"># Output: PE32 [UPX(modified)] — die identifies it but upx -d fails</span>\n<span class=\"G\">upx</span> -d sample.exe\n<span class=\"C\"># Error: \"NotPackedException: not packed by UPX\"</span>\n<span class=\"C\"># → Header bytes at offset 0x1E8 were overwritten</span>\n\n<span class=\"C\">## Step 2: Open in x64dbg, enable ScyllaHide</span>\nFile → Open → sample.exe\nPlugins → ScyllaHide → Maximum Profile\n\n<span class=\"C\">## Step 3: Find the PUSHAD/POPAD pattern</span>\n<span class=\"C\"># x64dbg lands at entry point — first instruction:</span>\n<span class=\"Y\">PUSHAD</span>    <span class=\"C\">← 0x60 — saves all registers (UPX signature)</span>\n<span class=\"C\"># This CONFIRMS UPX stub even with modified header</span>\n\n<span class=\"C\">## Step 4: Set hardware BP at ESP-4 (classic POPAD trick)</span>\n<span class=\"C\"># UPX ends with POPAD then JMP to OEP</span>\n<span class=\"C\"># After PUSHAD: ESP points to stack top</span>\n<span class=\"C\"># Set Hardware BP on ACCESS (read) at [ESP-4]</span>\n<span class=\"C\"># When POPAD executes, it reads from stack → BP fires</span>\n<span class=\"C\"># Then a JMP follows → that JMP's target = OEP</span>\nRight-click memory → Hardware BP → Read [esp-4]\n\n<span class=\"C\">## Step 5: Run → BP fires at POPAD → next is JMP to OEP</span>\nF9 → stops at POPAD\nF8 → step over POPAD  \n<span class=\"C\"># Now at JMP EAX (or JMP [address]) — this is the TAIL JUMP to OEP</span>\nF8 → step → YOU ARE AT OEP\n<span class=\"C\"># Verify: EIP should be in a different section</span>\n<span class=\"C\"># Disassembly should look like normal compiler code</span>\n<span class=\"C\"># First instruction: PUSH EBP / MOV EBP, ESP</span>\n\n<span class=\"C\">## Step 6: Dump + fix imports with Scylla</span>\nPlugins → Scylla → IAT Autosearch\nPlugins → Scylla → Get Imports\n<span class=\"C\"># All imports should resolve (green checkmarks)</span>\nPlugins → Scylla → Dump → save as \"unpacked.exe\"\nPlugins → Scylla → Fix Dump → select unpacked.exe\n<span class=\"C\"># → unpacked_SCY.exe = final result</span>\n\n<span class=\"C\">## Step 7: Verify in Ghidra</span>\n<span class=\"C\"># Import unpacked_SCY.exe</span>\n<span class=\"C\"># Entropy should be ~6.0 (normal)</span>\n<span class=\"C\"># Import table should be fully populated</span></div>\n  </div>\n\n  <!-- Lab 2: Custom XOR cryptor -->\n  <div class=\"card ca\" style=\"margin-bottom:12px\">\n    <div class=\"clabel\">Unpacking Lab 02 — Intermediate</div>\n    <div class=\"ctitle amber\">CUSTOM XOR CRYPTOR — EXTRACT THE KEY</div>\n    <div class=\"cbody\" style=\"margin-bottom:10px\"><strong>Scenario:</strong> Sample shows high entropy (7.8) across all sections, minimal imports. No known packer signature. You must locate the decryption loop, identify the key, and dump the decrypted payload.</div>\n    <div class=\"cb\">\n<span class=\"tag\">x64dbg — FlareVM</span>\n<span class=\"C\">## Step 1: Reconnaissance</span>\n<span class=\"G\">die</span> sample.exe           <span class=\"C\"># \"Unknown packer\"</span>\n<span class=\"C\"># Entropy > 7.8 across entire .text section</span>\n<span class=\"C\"># Imports: only LoadLibraryA, GetProcAddress (minimal)</span>\n\n<span class=\"C\">## Step 2: Open in Ghidra — find the decrypt loop</span>\n<span class=\"C\"># Look for: loop with XOR instruction</span>\n<span class=\"C\"># Pattern in decompiler:</span>\n<span class=\"C\">#   while (counter < size) {</span>\n<span class=\"C\">#     buffer[counter] ^= key[counter % key_len];</span>\n<span class=\"C\">#     counter++;</span>\n<span class=\"C\">#   }</span>\n\n<span class=\"C\">## Step 3: Note the address after decrypt loop</span>\n<span class=\"C\"># After loop completes, code jumps to decrypted payload</span>\n<span class=\"C\"># Or calls: CreateThread / VirtualAlloc + execute</span>\n\n<span class=\"C\">## Step 4: In x64dbg — BP on CALL (decrypt function)</span>\n<span class=\"C\"># Right-click the CALL → Set breakpoint</span>\nF9 → execution stops at decrypt function entry\n\n<span class=\"C\">## Step 5: Inspect arguments (key + ciphertext + size)</span>\n<span class=\"C\"># x86: stack at ESP+4, ESP+8, ESP+0xC</span>\n<span class=\"C\"># x64: RCX, RDX, R8 (first three args)</span>\n<span class=\"C\"># Dump the key buffer: right-click → Follow in Dump</span>\n\n<span class=\"C\">## Step 6: Run through decrypt loop</span>\n<span class=\"C\"># Option A: Step through (slow but educational)</span>\n<span class=\"C\"># Option B: BP at end of loop (fast)</span>\n<span class=\"C\">#   Find the instruction AFTER the loop body</span>\n<span class=\"C\">#   BP there → F9 → let loop complete</span>\n\n<span class=\"C\">## Step 7: Dump decrypted memory</span>\n<span class=\"C\"># Memory map shows new RWX region allocated</span>\n<span class=\"C\"># Right-click region → Dump Memory to File</span>\n<span class=\"C\"># The dump should start with 4D 5A (MZ) → it's a PE</span>\n<span class=\"C\"># → Run through Ghidra for full analysis</span>\n\n<span class=\"C\">## Optional: Reproduce decrypt offline</span>\n<span class=\"G\">python3</span> -c <span class=\"S\">\"\nkey = bytes.fromhex('deadbeef')  # from dump at key arg\nct  = open('encrypted_section.bin','rb').read()\nplain = bytes(b ^ key[i % len(key)] for i,b in enumerate(ct))\nopen('decrypted.bin','wb').write(plain)\n\"</span></div>\n  </div>\n\n  <!-- Lab 3: Anti-debug + multi-stage -->\n  <div class=\"card ca\">\n    <div class=\"clabel\">Unpacking Lab 03 — Advanced</div>\n    <div class=\"ctitle amber\">MULTI-STAGE DROPPER WITH ANTI-DEBUG CHAIN</div>\n    <div class=\"cbody\" style=\"margin-bottom:10px\"><strong>Scenario:</strong> Sample terminates immediately when run in a VM. Must defeat anti-debug + anti-VM chain, then unpack a two-stage dropper (stage 1 → decrypts stage 2 → injects into legitimate process).</div>\n    <div class=\"cb\">\n<span class=\"tag\">x64dbg — FlareVM — ADVANCED</span>\n<span class=\"C\">## Step 1: Aggressive ScyllaHide profile</span>\nPlugins → ScyllaHide → Options → Maximum\nEnable: RDTSC patch, heap flag clearing, TLS callback hiding\n\n<span class=\"C\">## Step 2: Handle TLS callbacks (run BEFORE WinMain)</span>\n<span class=\"C\"># TLS callbacks execute before EP — often contain anti-debug</span>\n<span class=\"C\"># x64dbg Options → Events → TLS Callbacks: checked</span>\n<span class=\"C\"># x64dbg now breaks on each TLS callback → inspect each one</span>\n\n<span class=\"C\">## Step 3: Trace through anti-analysis checks</span>\n<span class=\"C\"># Each check: IsDebuggerPresent → patch JNZ → JZ</span>\n<span class=\"C\"># CPUID → clear ECX bit 31 manually after each CPUID</span>\n<span class=\"C\"># Timing: ignore → ScyllaHide handles it</span>\n<span class=\"C\"># Registry check → already deleted VM keys from Step 1 of setup</span>\n\n<span class=\"C\">## Step 4: Find stage 1 → stage 2 handoff</span>\n<span class=\"C\"># BP on: VirtualAlloc, VirtualAllocEx (new memory)</span>\n<span class=\"C\"># First allocation = stage 2 landing zone</span>\n<span class=\"C\"># Watch for: WriteProcessMemory (injection into another process)</span>\n\n<span class=\"C\">## Step 5: Capture stage 2 before injection</span>\n<span class=\"C\"># At WriteProcessMemory BP:</span>\n<span class=\"C\"># Stack/args show: source buffer, dest process, size</span>\n<span class=\"C\"># Dump source buffer = stage 2 payload (decrypted)</span>\nRight-click buffer address → Dump Region → stage2.bin\n<span class=\"G\">file</span> stage2.bin    <span class=\"C\"># PE32? → analyze in Ghidra</span>\n\n<span class=\"C\">## Step 6: Analyze stage 2 in Ghidra</span>\n<span class=\"C\"># This is the real malware — C2 config, capability set</span>\n<span class=\"C\"># Extract: C2 IP/domain, encryption keys, command set</span>\n\n<span class=\"C\">## Step 7: pe-sieve post-execution</span>\n<span class=\"G\">pe-sieve.exe</span> /pid &lt;injected_pid&gt; /out dump/\n<span class=\"C\"># Dumps all PE artifacts from the injected process</span>\n<span class=\"C\"># Produces: process.dmp, module_XX.dll etc.</span></div>\n  </div>\n\n</div>\n</div>\n\n<!-- ═══════════════ ADVANCED TTPs ═══════════════ -->\n<div class=\"module z1\" id=\"mod-advanced\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-marker\">§6</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Cutting Edge //</div>\n      <div class=\"sh-title\">Advanced <span class=\"hl\">RE Techniques</span></div>\n      <div class=\"sh-desc\">Kernel-mode analysis, heap spray recognition, BYOVD driver analysis, and firmware-level reverse engineering concepts. The frontier of malware sophistication.</div>\n    </div>\n  </div>\n\n  <div class=\"g2\" style=\"margin-bottom:14px\">\n\n    <div class=\"card cc\">\n      <div class=\"clabel\">Kernel Mode Analysis</div>\n      <div class=\"ctitle cyan\">KERNEL DRIVER REVERSE ENGINEERING</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">BYOVD (Bring Your Own Vulnerable Driver) attacks use signed kernel drivers with exploitable vulnerabilities to gain ring-0 execution. Analyzing these requires understanding Windows kernel internals.</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"C\"># Identify kernel driver (PE with subsystem = Native)</span>\n<span class=\"G\">python3</span> -c <span class=\"S\">\"\nimport pefile\npe = pefile.PE('driver.sys')\nprint(pe.OPTIONAL_HEADER.Subsystem)  # 1 = Native\nprint(pe.FILE_HEADER.Machine)        # 0x8664 = x64\n\"</span>\n\n<span class=\"C\"># Key kernel exports to look for:</span>\n<span class=\"V\">DriverEntry</span>       <span class=\"C\">← entry point for kernel drivers</span>\n<span class=\"V\">DriverUnload</span>      <span class=\"C\">← cleanup</span>\n<span class=\"V\">IoCreateDevice</span>    <span class=\"C\">← creates device object</span>\n<span class=\"V\">MmMapIoSpace</span>      <span class=\"C\">← maps physical memory (privilege)</span>\n<span class=\"V\">MmGetPhysicalAddress</span> <span class=\"C\">← kernel memory ops</span>\n\n<span class=\"C\"># Ghidra analysis of .sys file:</span>\n<span class=\"C\"># Import file as PE format</span>\n<span class=\"C\"># Add Windows kernel type definitions</span>\n<span class=\"C\"># Scripts → ImportSymbolsScript → ntoskrnl.pdb</span>\n\n<span class=\"C\"># WinDbg kernel debugging (requires two machines):</span>\n<span class=\"C\"># Target machine: bcdedit /debug on</span>\n<span class=\"C\"># Host machine: windbg -k com:port=COM1,baud=115200</span>\n<span class=\"C\"># Load driver: .reload /f driver.sys</span>\n<span class=\"C\"># List modules: lm</span>\n<span class=\"C\"># Set BP: bp driver!DriverEntry</span></div>\n    </div>\n\n    <div class=\"card cc\">\n      <div class=\"clabel\">Heap Spray Recognition</div>\n      <div class=\"ctitle cyan\">HEAP SPRAY & EXPLOIT ANALYSIS</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">Browser exploits and document exploits often use heap spraying to reliably place shellcode at predictable addresses before the vulnerability is triggered.</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--cyan2)\">\n<span class=\"C\"># Heap spray recognition in JavaScript (browser exploit):</span>\n<span class=\"C\"># Allocate many large strings/ArrayBuffers</span>\n<span class=\"C\"># Fill heap with shellcode sleds</span>\n\n<span class=\"C\"># Typical JS heap spray pattern:</span>\nvar sled = <span class=\"S\">\"\\x90\\x90\"</span>.repeat(<span class=\"N\">0x1000</span>)  <span class=\"C\">// NOP sled</span>\nvar sc = <span class=\"S\">\"\\xfc\\xe8...\"</span>  <span class=\"C\">// shellcode</span>\nvar chunk = sled + sc\nvar spray = []\n<span class=\"K\">for</span> (var i = <span class=\"N\">0</span>; i &lt; <span class=\"N\">0x200</span>; i++) {\n    spray.push(chunk.repeat(<span class=\"N\">0x40</span>))\n}\n<span class=\"C\">// Heap now saturated with shellcode at predictable addresses</span>\n<span class=\"C\">// Exploit jumps to 0x0c0c0c0c (common spray target)</span>\n\n<span class=\"C\"># Analysis: capture exploit in Wireshark/Fiddler</span>\n<span class=\"C\"># Extract JavaScript → beautify with js-beautify</span>\n<span class=\"C\"># Decode base64/hex payload embedded in JS</span>\n<span class=\"G\">npm</span> install -g js-beautify\n<span class=\"G\">js-beautify</span> exploit.js > readable.js\n\n<span class=\"C\"># Dynamic: Firefox/Chrome devtools</span>\n<span class=\"C\"># Debugger → Breakpoints → XHR/fetch breaks</span></div>\n    </div>\n  </div>\n\n  <div class=\"card\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Analysis Reference</div>\n    <div class=\"ctitle\">ADVANCED RE TOOL CHEATSHEET</div>\n    <table class=\"dtable\">\n      <tr><th>TOOL</th><th>USE CASE</th><th>COMMAND / NOTES</th></tr>\n      <tr>\n        <td><strong>unipacker</strong></td>\n        <td>Auto-unpack UPX, ASPack, PEtite, FSG, MPRESS</td>\n        <td><code>unipacker sample.exe -o out/</code></td>\n      </tr>\n      <tr>\n        <td><strong>pe-sieve</strong></td>\n        <td>Scan live process for hollowing/injection</td>\n        <td><code>pe-sieve /pid 1234 /out dump/</code></td>\n      </tr>\n      <tr>\n        <td><strong>speakeasy</strong></td>\n        <td>Emulate shellcode without execution</td>\n        <td><code>speakeasy -t sc.bin -r -a x86</code></td>\n      </tr>\n      <tr>\n        <td><strong>ScyllaHide</strong></td>\n        <td>Defeat all common anti-debug in x64dbg</td>\n        <td>x64dbg plugin, Maximum profile</td>\n      </tr>\n      <tr>\n        <td><strong>de4dot</strong></td>\n        <td>Deobfuscate .NET malware</td>\n        <td><code>de4dot sample.exe -o clean.exe</code></td>\n      </tr>\n      <tr>\n        <td><strong>dnSpy</strong></td>\n        <td>Debug .NET malware at IL level</td>\n        <td>Full debugger for .NET, better than x64dbg for managed code</td>\n      </tr>\n      <tr>\n        <td><strong>D-810 (Ghidra)</strong></td>\n        <td>Deobfuscate control flow flattening in Ghidra</td>\n        <td>Plugin: github.com/jpenalbae/d810</td>\n      </tr>\n      <tr>\n        <td><strong>HashDB (Ghidra)</strong></td>\n        <td>Resolve API hash constants automatically</td>\n        <td>Right-click hash → HashDB Lookup</td>\n      </tr>\n      <tr>\n        <td><strong>Detect-It-Easy</strong></td>\n        <td>Identify packer, compiler, protector</td>\n        <td><code>die sample.exe</code> — extremely fast</td>\n      </tr>\n      <tr>\n        <td><strong>FLOSS v3</strong></td>\n        <td>Extract obfuscated strings (stack, decoded, tight loop)</td>\n        <td><code>floss sample.exe --only decoded</code></td>\n      </tr>\n      <tr>\n        <td><strong>CFF Explorer</strong></td>\n        <td>Manual PE header surgery</td>\n        <td>Fix sections, headers, timestamps after unpacking</td>\n      </tr>\n      <tr>\n        <td><strong>WinDbg</strong></td>\n        <td>Kernel debugging (.sys drivers, BYOVD)</td>\n        <td>Requires two-machine setup or VM serial debug</td>\n      </tr>\n    </table>\n  </div>\n\n  <div class=\"card\">\n    <div class=\"clabel\">Sample Acquisition for Advanced RE Labs</div>\n    <div class=\"ctitle\">FINDING SAMPLES TO PRACTICE ON</div>\n    <div class=\"cb\">\n<span class=\"C\"># MalwareBazaar — search by packer/tag</span>\n<span class=\"C\"># Browser: bazaar.abuse.ch/browse/?tag=upx</span>\n<span class=\"G\">curl</span> -X POST https://mb-api.abuse.ch/api/v1/ \\\n    -d <span class=\"S\">'query=get_taginfo&tag=upx&limit=20'</span>\n\n<span class=\"C\"># For .NET samples (great for deobfuscation practice):</span>\n<span class=\"C\"># Tag: AgentTesla, AsyncRAT, Formbook — all .NET</span>\n<span class=\"G\">curl</span> -X POST https://mb-api.abuse.ch/api/v1/ \\\n    -d <span class=\"S\">'query=get_taginfo&tag=agenttesla&limit=10'</span>\n\n<span class=\"C\"># Malware-Traffic-Analysis.net — PCAPs with malware</span>\n<span class=\"C\"># Download exercise ZIP → analyze PCAP + binary</span>\n<span class=\"C\"># Password always: infected</span>\n\n<span class=\"C\"># PolySwarm (threat intel + sample download)</span>\n<span class=\"C\"># Lookup hash → download sample → analyze</span>\n\n<span class=\"C\"># IMPORTANT: hash before analyzing, store in password zip</span>\n<span class=\"G\">sha256sum</span> sample.exe\n<span class=\"G\">zip</span> -P infected sample_$(sha256sum sample.exe | cut -c1-8).zip sample.exe</div>\n  </div>\n\n</div>\n</div>\n\n<!-- ═══════════════ QUIZ ═══════════════ -->\n<div class=\"module z1\" id=\"mod-quiz\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-marker\">§∞</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Competency Check //</div>\n      <div class=\"sh-title\">Module 06 <span class=\"hl\">Exam</span></div>\n      <div class=\"sh-desc\">Ten questions. Scenario-based. Covers packers, anti-analysis, shellcode internals, obfuscation, and advanced RE technique selection.</div>\n    </div>\n  </div>\n\n  <div id=\"quiz-container\"></div>\n\n  <div class=\"score-panel\">\n    <div class=\"score-big\" id=\"score-big\">—</div>\n    <div class=\"score-sub\" id=\"score-sub\">ANSWER QUESTIONS TO TRACK SCORE</div>\n    <div class=\"score-bar\"><div class=\"score-fill\" id=\"score-fill\" style=\"width:0%\"></div></div>\n    <button class=\"reset-btn\" onclick=\"resetQuiz()\">RESET EXAM</button>\n  </div>\n\n</div>\n</div>\n\n<script>\nfunction sw(id, btn) {\n  document.querySelectorAll('.module').forEach(m => m.classList.remove('active'));\n  document.querySelectorAll('.ntab').forEach(t => t.classList.remove('active'));\n  document.getElementById('mod-' + id).classList.add('active');\n  btn.classList.add('active');\n  window.scrollTo({ top: 0, behavior: 'smooth' });\n}\nfunction iTab(id, btn) {\n  const mod = btn.closest('.module');\n  mod.querySelectorAll('.itab').forEach(t => t.classList.remove('active'));\n  mod.querySelectorAll('.ipanel').forEach(p => p.classList.remove('active'));\n  btn.classList.add('active');\n  document.getElementById('ip-' + id).classList.add('active');\n}\n\nconst Qs = [\n  {\n    q: \"A packed sample shows entropy 7.92 across all sections. Detect-It-Easy shows 'Unknown packer'. The first instruction at the entry point is 0x60 (PUSHAD). What is the fastest reliable unpacking approach?\",\n    opts: [\n      \"Run strings — high entropy means no readable strings; skip to dynamic analysis\",\n      \"The 0x60 PUSHAD is the UPX stub signature. Set a hardware BP on ESP-4 access (stack memory), run, land at POPAD, step one more → arrive at OEP. Dump + fix imports with Scylla. Even with 'Unknown' in DIE, PUSHAD at EP + UPX sections = modified UPX\",\n      \"Use de4dot — it handles all unknown packers automatically\",\n      \"Set a BP on every import call to intercept the unpacking\"\n    ],\n    correct: 1,\n    explain: \"<strong>PUSHAD (0x60) at entry point is the UPX stub signature.</strong> Even when the UPX magic bytes are overwritten (causing DIE to say 'Unknown' and upx -d to fail), the stub code is intact. The PUSHAD+POPAD pattern is UPX's register save/restore around the decompression routine. The stack-memory hardware BP trick: after PUSHAD, ESP points to the saved register block. Setting a HW BP on [ESP-4] causes a break when POPAD reads those registers back — immediately followed by the JMP to OEP. This technique works on virtually all PUSHAD-based packers, not just UPX.\"\n  },\n  {\n    q: \"A sample calls IsDebuggerPresent() and terminates if it returns non-zero. You've installed ScyllaHide. The sample STILL terminates. What additional step is required?\",\n    opts: [\n      \"ScyllaHide should handle this automatically — try reinstalling it\",\n      \"The termination may be triggered by a TLS callback running BEFORE the entry point. Enable 'TLS Callbacks' breakpoints in x64dbg Options → Events, so x64dbg breaks at each TLS callback before EP is reached\",\n      \"IsDebuggerPresent cannot be patched — use bare-metal analysis instead\",\n      \"Add more memory to the VM — IsDebuggerPresent sometimes fails due to RAM limits\"\n    ],\n    correct: 1,\n    explain: \"<strong>TLS (Thread Local Storage) callbacks execute before the entry point.</strong> x64dbg by default does NOT break on TLS callbacks — it only breaks at the traditional Entry Point. Sophisticated malware places anti-debug checks in TLS callbacks precisely because many analysts and some tools miss them. ScyllaHide patches the Win32 API hooks at EP — but TLS callbacks run before those hooks are in effect. Fix: Options → Events → TLS Callbacks → checked. x64dbg now breaks at each TLS callback, letting you inspect and patch the anti-debug check before it fires.\"\n  },\n  {\n    q: \"You're analyzing shellcode extracted from a memory dump. You find this byte sequence at the start: E8 00 00 00 00 58. In x86 assembly this is: CALL +0 / POP EAX. What is this pattern and why is it significant?\",\n    opts: [\n      \"A null pointer dereference bug in the shellcode — it will crash before executing\",\n      \"GetPC (Get Program Counter) — CALL +0 pushes EIP onto the stack, POP EAX retrieves it. EAX now holds the current instruction address. This makes the shellcode position-independent, allowing it to calculate the addresses of embedded strings and code using offsets from EAX\",\n      \"An anti-debug trick — the 00 00 00 00 bytes form a NOP sled to confuse disassemblers\",\n      \"An import table stub — CALL +0 is how shellcode calls Windows APIs\"\n    ],\n    correct: 1,\n    explain: \"<strong>GetPC (Get Program Counter) — the shellcode self-location bootstrap.</strong> CALL pushes the address of the NEXT instruction (EIP) onto the stack, then immediately jumps there (CALL +0 = call relative +0). POP EAX retrieves that address. Result: EAX = address of the POP instruction itself = shellcode's current location in memory. Since shellcode has no fixed load address (position-independent code), it MUST know its own address to access embedded strings, configuration data, and secondary payloads using relative offsets. Everything in the shellcode is accessed as [EAX + offset]. This is seen in virtually every piece of real-world shellcode — recognizing it instantly tells you the shellcode is about to start resolving its internal data.\"\n  },\n  {\n    q: \"Malware implements RDTSC timing checks. ScyllaHide is enabled with the RDTSC patch active, but stepping through the code in x64dbg still sometimes triggers the timing check and alters behavior. What is the most reliable workaround?\",\n    opts: [\n      \"Increase your CPU speed — faster hardware makes RDTSC deltas smaller\",\n      \"Switch from software breakpoints (which modify code with 0xCC and require exception handling overhead) to hardware breakpoints (DR0-DR3 registers). Hardware BPs don't slow execution — the CPU hits them at native speed, producing tiny RDTSC deltas that won't trigger the timing threshold\",\n      \"Disable RDTSC in BIOS settings to prevent the instruction from executing\",\n      \"Run the sample without any breakpoints and dump memory after execution\"\n    ],\n    correct: 1,\n    explain: \"<strong>Hardware breakpoints don't stall the CPU; software breakpoints do.</strong> Software BPs work by replacing the instruction byte with 0xCC (INT3), which triggers an exception — the debugger's exception handler runs, which adds significant latency (thousands of cycles). RDTSC before and after a software BP will show a huge delta. Hardware BPs are handled differently: the CPU's debug registers (DR0-DR3) contain addresses to watch. When execution hits a HW BP address, a debug exception fires with minimal overhead — often only a few hundred cycles. Combined with ScyllaHide's RDTSC patching (returns synthetic small deltas), hardware BPs make timing checks much harder to trigger. In x64dbg: right-click instruction → Set Hardware Breakpoint → Execute, or Ctrl+H.\"\n  },\n  {\n    q: \"You extract a PE from a .NET malware sample. Running de4dot produces an output file but the methods still have names like 'a', 'b', 'c' and strings are still encrypted. What does this indicate and what is the next step?\",\n    opts: [\n      \"de4dot failed completely — the file is not actually .NET\",\n      \"The obfuscator used is not in de4dot's supported list, OR it uses a custom string decryption method. Next: open in dnSpy, set breakpoints on the static constructor (.cctor) where string initialization happens, run, and inspect the string table after decryption runs\",\n      \"The sample is packed — run unipacker first before de4dot\",\n      \"de4dot only renames methods if you use the --rename flag\"\n    ],\n    correct: 1,\n    explain: \"<strong>Custom or unsupported obfuscator — debug-based string extraction.</strong> de4dot handles ~20 known .NET obfuscators statically. When it can't fully deobfuscate (custom scheme, unsupported version), you get partial results: de4dot may clean up some control flow but can't decrypt strings it doesn't recognize. The workaround: dnSpy is a .NET debugger that lets you set breakpoints on IL code. The static constructor (.cctor) of each class runs before the first class use — this is where string decryption typically happens. Set a breakpoint at the start of .cctor, run, inspect the string table after it executes. The strings will be decrypted in memory and visible in dnSpy's Locals/Watch window. This works regardless of the encryption algorithm because you observe the result after decryption, not reverse the encryption.\"\n  },\n  {\n    q: \"In Ghidra, a function shows hundreds of basic blocks all converging to a single central block, which then dispatches to one of many blocks based on a variable value. All blocks end with: [state_var] = constant; goto dispatcher. What obfuscation technique is this and which tool addresses it?\",\n    opts: [\n      \"This is an optimized switch statement — Ghidra is correctly displaying the compiler's output\",\n      \"Control Flow Flattening (CFF) — the original structured code has been transformed into a dispatcher-based state machine. D-810 (Ghidra plugin) or miasm can reconstruct the original control flow by symbolic execution through the dispatcher\",\n      \"This is a polymorphic engine — the dispatcher regenerates code each time\",\n      \"This is a heap spray — the central block is the NOP sled target\"\n    ],\n    correct: 1,\n    explain: \"<strong>Control Flow Flattening (CFF) — the dispatcher-state machine transform.</strong> Every basic block's natural successor is replaced with: (1) update a state variable to a constant, (2) jump back to the central dispatcher. The dispatcher reads the state variable and jumps to the appropriate block. This makes Ghidra's control flow graph look like a wheel with the dispatcher at the center — completely hiding the original if/else/loop structure. D-810 (github.com/jpenalbae/d810) performs symbolic execution through the dispatcher to determine the TRUE successor of each block and reconstructs the original edges. The result is a readable control flow graph. miasm provides similar capabilities via Python scripting for more customized analysis. Without these tools, manually trace the state_var constants to map each block's true successor.\"\n  },\n  {\n    q: \"A shellcode sample contains the value 0xEC0E4E8E as a constant pushed before calling a function. The function appears to iterate over a module's export table. What is 0xEC0E4E8E and how do you resolve it to an API name?\",\n    opts: [\n      \"It's a memory address — dereference it in x64dbg to find the target\",\n      \"It's a ROR13 AddHash of an API name — hash each export name of kernel32.dll using the ROR13 algorithm until you find the match, or use the HashDB Ghidra plugin to look it up automatically. 0xEC0E4E8E = LoadLibraryA\",\n      \"It's an XOR key — XOR all bytes with 0xEC0E4E8E to decrypt the next data blob\",\n      \"It's an NTSTATUS code — look it up in Windows NTSTATUS documentation\"\n    ],\n    correct: 1,\n    explain: \"<strong>ROR13 AddHash — the most common shellcode API hashing algorithm.</strong> Shellcode can't import APIs by name (no import table). Instead, it walks the PEB to find loaded modules and iterates their export tables. Each export name is hashed using ROR13 (rotate right 13 bits) + add each byte, until the hash matches the target constant. 0xEC0E4E8E is the well-known ROR13 hash of 'LoadLibraryA\\\\x00'. Resolution tools: (1) HashDB Ghidra plugin — right-click the constant → HashDB Lookup → automatically identifies the algorithm and function name. (2) Python script: hash every export in common DLLs and build a lookup table. (3) Online HashDB at hashdb.openanalysis.net. Once resolved, rename the constant in Ghidra to 'HASH_LoadLibraryA' — the decompiler becomes dramatically more readable.\"\n  },\n  {\n    q: \"You're debugging a two-stage dropper. Stage 1 decrypts stage 2 and calls WriteProcessMemory to inject it into svchost.exe. You want to capture stage 2 before injection. Where exactly do you set your breakpoint and what do you dump?\",\n    opts: [\n      \"Set a BP on svchost.exe's entry point — stage 2 will appear there after injection\",\n      \"Set a BP on WriteProcessMemory. When it fires, the source buffer argument (lpBuffer, stack arg 3 on x86 / R8 on x64) points to the fully decrypted stage 2 PE in memory. Dump [lpBuffer] for lpNumberOfBytesWritten bytes — this is the unobfuscated payload\",\n      \"Set a BP on ReadProcessMemory — stage 2 is read from the file system before injection\",\n      \"Set a BP on ExitProcess — stage 2 will be in memory just before the process exits\"\n    ],\n    correct: 1,\n    explain: \"<strong>WriteProcessMemory BP — capture the payload at the injection moment.</strong> WriteProcessMemory signature: WriteProcessMemory(hProcess, lpBaseAddress, lpBuffer, nSize, lpNumberOfBytesWritten). When BP fires: lpBuffer (3rd argument — ESP+12 on x86, R8 on x64) points to the source data = decrypted stage 2 PE, completely deobfuscated and ready to execute. nSize (4th arg) = exact number of bytes to dump. Right-click the buffer address in x64dbg → Follow in Dump → select the region → Dump to File. The file should start with 4D 5A (MZ) and be a valid PE that you can analyze in Ghidra. This technique works for any injection method that uses WriteProcessMemory — it's always the last moment before the payload disappears into the target process's address space.\"\n  },\n  {\n    q: \"A .NET RAT uses string literals like 'ConnectToHost', 'UploadFile', 'Screenshot' — but all appear XOR-encrypted in the binary. In dnSpy, you can see these strings are decrypted by a static method called 'SR.s(int index)'. What is the most efficient way to extract all decrypted strings without manually calling s() for each index?\",\n    opts: [\n      \"Decompile the SR.s() method in dnSpy and re-implement it in Python — then iterate all indices\",\n      \"Add a debug breakpoint at the start of SR.s() — strings will decrypt one at a time as they're needed during execution\",\n      \"Patch the binary to call Console.WriteLine(SR.s(i)) for each index in a loop, compile and run in the VM — output captures all strings at once. Or: use dnSpy Edit → Modify Method to add a logging hook to SR.s() that prints each decrypted string as it's called\",\n      \"Delete the encryption — remove the static constructor to bypass decryption\"\n    ],\n    correct: 2,\n    explain: \"<strong>Dynamic string extraction via code patching or hooking.</strong> The most efficient approach: (1) In dnSpy, find the Main() method (or any early method). Click Edit C# (right-click → Edit Method). Add a loop: <code>for (int i=0; i<1000; i++) { try { Console.WriteLine(i + \\\":\\\" + SR.s(i)); } catch {} }</code> before the first line. Compile. Run in the VM. Every string dumps to console. (2) Alternative: add a Console.WriteLine call inside SR.s() itself — then run normally and all strings print as they're decrypted. This approach requires running the malware (in isolated VM) but is far faster than manually re-implementing the decryption. The try/catch handles out-of-bounds indices gracefully. This technique extracts ALL strings in one execution without reversing the encryption algorithm.\"\n  },\n  {\n    q: \"After unpacking a sample with the OEP method (dumped + fixed imports with Scylla), you load the dump into Ghidra but the decompiler shows many calls to 'FUN_00000000' (null address) and the import table seems corrupt. What likely went wrong and how do you fix it?\",\n    opts: [\n      \"The dump is encrypted — run it through unipacker before loading into Ghidra\",\n      \"Scylla's IAT fix was incomplete — some import thunks weren't resolved. Fix: (1) In Scylla, use 'IAT Autosearch' again with the process still running at OEP, (2) Manually add missing imports via 'Add Import' in Scylla for any that show '??' or null, (3) Alternatively, use CFF Explorer to manually fix the import table in the dumped PE by adding the missing DLL/function entries\",\n      \"The dump is the wrong architecture — re-dump as 64-bit instead of 32-bit\",\n      \"Ghidra doesn't support dumped PEs — use IDA Pro instead\"\n    ],\n    correct: 1,\n    explain: \"<strong>Incomplete IAT (Import Address Table) fix — the most common post-dump issue.</strong> Scylla's IAT Autosearch works by scanning the dumped PE for pointers to resolved API addresses and tracing them back to the DLL+function name. It fails when: (1) The packer uses delayed imports, (2) Some APIs are called via computed pointers (not the standard IAT), (3) Anti-dump protection modified the memory layout. Fix sequence: with the process still running at OEP (don't close it!), run Scylla IAT Autosearch again. For each entry showing '??' or null: right-click → 'Get Imports' manually, or use 'Add Import' to specify the DLL and function name. CFF Explorer can also manually repair import directory entries. The key insight: Scylla works best when the process is still alive at OEP — closing it loses the resolved API address information in memory.\"\n  }\n];\n\nlet answered = new Array(Qs.length).fill(false);\nlet score = 0;\nconst topics = ['Packer Recognition','Anti-Debug TLS','Shellcode GetPC','RDTSC Bypass','.NET Deobfuscation','Control Flow Flattening','API Hashing','Injection Capture','String Extraction','IAT Repair'];\n\nfunction buildQuiz() {\n  const c = document.getElementById('quiz-container');\n  c.innerHTML = '';\n  Qs.forEach((q, qi) => {\n    const d = document.createElement('div');\n    d.className = 'qcard';\n    d.innerHTML = `\n      <div class=\"qnum\">Q${String(qi+1).padStart(2,'0')} · ${topics[qi]}</div>\n      <div class=\"qtext\">${q.q}</div>\n      <div class=\"qopts\">${q.opts.map((o,oi) => `<button class=\"qopt\" onclick=\"ans(${qi},${oi},this)\">${String.fromCharCode(65+oi)}. ${o}</button>`).join('')}</div>\n      <div class=\"qexplain\" id=\"exp-${qi}\">${q.explain}</div>\n    `;\n    c.appendChild(d);\n  });\n  updateScore();\n}\n\nfunction ans(qi, oi, btn) {\n  if (answered[qi]) return;\n  answered[qi] = true;\n  btn.closest('.qopts').querySelectorAll('.qopt').forEach(b => b.classList.add('locked'));\n  if (oi === Qs[qi].correct) { btn.classList.add('correct'); score++; }\n  else { btn.classList.add('wrong'); btn.closest('.qopts').querySelectorAll('.qopt')[Qs[qi].correct].classList.add('correct'); }\n  document.getElementById('exp-' + qi).classList.add('show');\n  updateScore();\n}\n\nfunction updateScore() {\n  const done = answered.filter(Boolean).length;\n  const big = document.getElementById('score-big');\n  const sub = document.getElementById('score-sub');\n  const fill = document.getElementById('score-fill');\n  if (done === 0) { big.textContent = '—'; sub.textContent = 'ANSWER QUESTIONS TO TRACK SCORE'; return; }\n  const pct = Math.round(score / done * 100);\n  big.textContent = `${score}/${done}`;\n  const rem = Qs.length - done;\n  sub.textContent = rem > 0 ? `${pct}% CORRECT · ${rem} REMAINING` : pct >= 80 ? `${pct}% · ADVANCED RE CERTIFIED` : pct >= 60 ? `${pct}% · REVIEW WEAK AREAS` : `${pct}% · REPEAT MODULE`;\n  fill.style.width = pct + '%';\n  fill.style.background = pct >= 80 ? '#0aff5a' : pct >= 60 ? '#ffb800' : '#ff1a2e';\n}\n\nfunction resetQuiz() {\n  answered = new Array(Qs.length).fill(false);\n  score = 0;\n  buildQuiz();\n}\n\nbuildQuiz();\n</script>\n</body>\n</html>\n";

export default advancedReverseEngineeringHtml;
